_ICON_B64 = ""

def _get_icon_path():
    import base64 as _b64, tempfile as _tmp
    try:
        data = _b64.b64decode(_ICON_B64)
        here = os.path.dirname(os.path.abspath(
            sys.executable if getattr(sys,'frozen',False) else __file__))
        p = os.path.join(here, '_scarlett_icon.ico')
        with open(p,'wb') as f: f.write(data)
        return p
    except:
        try:
            tf = _tmp.NamedTemporaryFile(suffix='.ico',delete=False)
            tf.write(_b64.b64decode(_ICON_B64)); tf.close()
            return tf.name
        except: return None

_ICON_PATH = _get_icon_path()


