# ГРОМКОСТЬ
# ══════════════════════════════════════════════════════════
class VolumeControl:
    """Управление громкостью через pycaw или PowerShell"""
    def __init__(self):
        self._vol = None
        self._init()

    def _init(self):
        try:
            from pycaw.pycaw import AudioUtilities, IAudioEndpointVolume
            from comtypes import CLSCTX_ALL
            # Метод 1: через AudioUtilities.GetSpeakers (новые версии)
            try:
                device = AudioUtilities.GetSpeakers()
                interface = device.Activate(
                    IAudioEndpointVolume._iid_, CLSCTX_ALL, None)
                self._vol = cast(interface, POINTER(IAudioEndpointVolume))
                test = self._vol.GetMasterVolumeLevelScalar()
                print(f"[Volume] pycaw v1 OK, уровень: {int(test*100)}%")
                return
            except Exception as e1:
                print(f"[Volume] pycaw v1 ошибка: {e1}")

            # Метод 2: через comtypes напрямую (старые версии pycaw)
            try:
                import comtypes.client
                MMDeviceEnumerator = comtypes.client.CreateObject(
                    "{BCDE0395-E52F-467C-8E3D-C4579291692E}",
                    interface=comtypes.IUnknown)
                # Получаем IMMDeviceEnumerator
                from pycaw.pycaw import IMMDeviceEnumerator, EDataFlow, ERole
                enumerator = MMDeviceEnumerator.QueryInterface(IMMDeviceEnumerator)
                device = enumerator.GetDefaultAudioEndpoint(
                    EDataFlow.eRender.value, ERole.eMultimedia.value)
                interface = device.Activate(
                    IAudioEndpointVolume._iid_, CLSCTX_ALL, None)
                self._vol = cast(interface, POINTER(IAudioEndpointVolume))
                test = self._vol.GetMasterVolumeLevelScalar()
                print(f"[Volume] pycaw v2 OK, уровень: {int(test*100)}%")
                return
            except Exception as e2:
                print(f"[Volume] pycaw v2 ошибка: {e2}")

        except ImportError:
            print("[Volume] pycaw не установлен: pip install pycaw comtypes")
        except Exception as e:
            print(f"[Volume] pycaw недоступен: {e}")
        self._vol = None

    def set(self, level: int):
        level = max(0, min(100, level))
        # Способ 1: pycaw
        if self._vol:
            try:
                self._vol.SetMasterVolumeLevelScalar(level / 100.0, None)
                print(f"[Volume] pycaw -> {level}%")
                return True
            except Exception as e:
                print(f"[Volume] pycaw ошибка: {e}")
                self._vol = None
                self._init()
                if self._vol:
                    try:
                        self._vol.SetMasterVolumeLevelScalar(level / 100.0, None)
                        return True
                    except:
                        pass
        # Способ 2: Python ctypes напрямую — без PowerShell
        try:
            import comtypes.client
            from comtypes import CLSCTX_ALL
            # Создаём enumerator напрямую через CoCreateInstance
            CLSID_MMDeviceEnumerator = "{BCDE0395-E52F-467C-8E3D-C4579291692E}"
            IID_IMMDeviceEnumerator  = "{BCDE0395-E52F-467C-8E3D-C4579291692E}"
            from pycaw.pycaw import AudioUtilities, IAudioEndpointVolume
            device = AudioUtilities.GetSpeakers()
            iface = device.Activate(IAudioEndpointVolume._iid_, CLSCTX_ALL, None)
            vol_ctrl = cast(iface, POINTER(IAudioEndpointVolume))
            vol_ctrl.SetMasterVolumeLevelScalar(level / 100.0, None)
            self._vol = vol_ctrl  # обновляем кэш
            print(f"[Volume] ctypes retry -> {level}%")
            return True
        except Exception as e:
            print(f"[Volume] ctypes retry: {e}")

        # Способ 3: NirCmd (если установлен)
        try:
            v = int(level / 100 * 65535)
            r = subprocess.run(["nircmd", "setsysvolume", str(v)],
                capture_output=True, timeout=3,
                creationflags=subprocess.CREATE_NO_WINDOW)
            if r.returncode == 0:
                print(f"[Volume] nircmd -> {level}%")
                return True
        except:
            pass

        # Последний резерв — регулировка громкости клавишами через ctypes
        try:
            # Сначала обнуляем (50 нажатий vol down)
            for _ in range(50):
                ctypes.windll.user32.keybd_event(0xAE, 0, 0, 0)
                ctypes.windll.user32.keybd_event(0xAE, 0, 2, 0)
            # Потом поднимаем до нужного (каждые 2% = 1 нажатие)
            steps = level // 2
            for _ in range(steps):
                ctypes.windll.user32.keybd_event(0xAF, 0, 0, 0)
                ctypes.windll.user32.keybd_event(0xAF, 0, 2, 0)
            print(f"[Volume] keybd fallback -> {level}%")
            return True
        except Exception as e:
            print(f"[Volume] keybd ошибка: {e}")
        print("[Volume] Все методы не сработали. Запусти fix_volume.bat!")
        return False

    def get(self) -> int:
        if self._vol:
            try:
                return int(self._vol.GetMasterVolumeLevelScalar() * 100)
            except:
                pass
        return 50

    def mute(self):
        if self._vol:
            try:
                self._vol.SetMute(True, None)
                print("[Volume] mute via pycaw")
                return
            except:
                pass
        ctypes.windll.user32.keybd_event(0xAD, 0, 0, 0)
        ctypes.windll.user32.keybd_event(0xAD, 0, 2, 0)
        print("[Volume] mute via keybd")

    def unmute(self):
        if self._vol:
            try:
                self._vol.SetMute(False, None)
                print("[Volume] unmute via pycaw")
                return
            except:
                pass
        ctypes.windll.user32.keybd_event(0xAD, 0, 0, 0)
        ctypes.windll.user32.keybd_event(0xAD, 0, 2, 0)
        print("[Volume] unmute via keybd")
