        if any(x in al for x in ["дискорд","discord","де скотт","дискот","дисскорд"]):
            import glob as _g
            local  = os.environ.get("LOCALAPPDATA", "")
            roaming = os.environ.get("APPDATA", "")
            # Discord устанавливается в app-X.X.X подпапку
            patterns = [
                os.path.join(local,   "Discord", "app-*", "Discord.exe"),
                os.path.join(roaming, "Discord", "app-*", "Discord.exe"),
                os.path.join(local,   "Discord", "Discord.exe"),
            ]
            found = []
            for pat in patterns:
                found += _g.glob(pat)
            if found:
                found.sort(reverse=True)
