# TTS — edge-tts (Microsoft бесплатный живой голос)
# pip install edge-tts pygame
# ══════════════════════════════════════════════════════════
class TTS:
    # Русские женские голоса edge-tts (бесплатно, онлайн)
    VOICES = [
        "ru-RU-SvetlanaNeural",   # Светлана — мягкий тёплый
        "ru-RU-DariyaNeural",     # Дария — молодой живой
    ]

    def __init__(self):
        self._lock = threading.Lock()
        self._busy = False
        self._voice = self.VOICES[0]
        self._use_edge = False
        self._pygame_ok = False
        self._pyttsx_engine = None
        self._init()

    def _init(self):
        # Пробуем edge-tts
        try:
            import edge_tts
            self._use_edge = True
            print(f"[TTS] edge-tts OK, голос: {self._voice}")
        except ImportError:
            print("[TTS] edge-tts не установлен, пробую pyttsx3...")

        # pygame для воспроизведения mp3 от edge-tts
        if self._use_edge:
            try:
                import pygame
                pygame.mixer.init()
                self._pygame_ok = True
                print("[TTS] pygame mixer OK")
            except Exception as e:
                print(f"[TTS] pygame недоступен: {e}")
                self._use_edge = False  # без pygame edge не работает

        # Fallback: pyttsx3
        if not self._use_edge:
            try:
                import pyttsx3
                eng = pyttsx3.init()
                voices = eng.getProperty("voices")
                for v in voices:
                    if any(k in v.name.lower() for k in ["irina","elena","anna","milena"]):
                        eng.setProperty("voice", v.id)
                        break
                eng.setProperty("rate", 170)
                eng.setProperty("volume", 0.95)
                self._pyttsx_engine = eng
                print(f"[TTS] pyttsx3 fallback OK")
            except Exception as e:
                print(f"[TTS] pyttsx3 тоже недоступен: {e}")

    def speak(self, text: str, done_cb=None):
        if self._busy:
            if done_cb: done_cb()
            return
        if self._use_edge and self._pygame_ok:
            threading.Thread(target=self._speak_edge,
                              args=(text, done_cb), daemon=True).start()
        elif self._pyttsx_engine:
            threading.Thread(target=self._speak_pyttsx,
                              args=(text, done_cb), daemon=True).start()
        else:
            if done_cb: done_cb()

    # Словарь транслитерации часто встречающихся слов
    _EN_TO_RU = {
        "discord":"Дискорд","telegram":"Телеграм","youtube":"Ютуб",
        "yandex":"Яндекс","spotify":"Спотифай","steam":"Стим",
        "chrome":"Хром","firefox":"Фаерфокс","windows":"Виндовс",
        "ok":"окей","yes":"да","no":"нет","hello":"привет",
        "scarlett":"Скарлетт","shuffle":"шаффл","skip":"скип",
        "play":"плей","stop":"стоп","ai":"ИИ","pc":"компьютер",
        "wi-fi":"вай-фай","wifi":"вай-фай","vpn":"ВПН",
        "cpu":"процессор","gpu":"видеокарта","ram":"оперативка",
        "pdf":"пдф","mp3":"эмпэтри","mp4":"эмпэчетыре",
        "url":"ссылка","http":"хттп","https":"хттпс",
        "onemore":"Ванмор",
    }

    @staticmethod
    def _strip_emoji(text: str) -> str:
        """Готовит текст к озвучке: убирает emoji и чистит символы"""
        import re as _re

        # Emoji через unicode escapes (надёжно на всех питонах)
        emoji_re = _re.compile(
            u"[😀-🙏"
            u"🌀-🗿"
            u"🚀-🛿"
            u"🇠-🇿"
            u"☀-➿"
            u"🤀-🧿"
            u"🨀-🫿"
            u"✂-➰"
            u"Ⓜ-🉑]+",
            flags=_re.UNICODE)
        text = emoji_re.sub("", text)

        # Тире и разделители → пауза (запятая читается голосом)
        text = text.replace("—", ", ")
        text = text.replace("–", ", ")
        text = text.replace("|", ", ")
        text = text.replace("•", ", ")
        text = text.replace("·", ", ")

        # Убираем символы которые TTS не читает
        text = _re.sub(r"[✓✗✔✘►▶⏸⏭⏮⟳↻↺◆★☆→←↑↓«»]", "", text)

        # Точки подряд → одна точка
        text = _re.sub(r"\.{2,}", ".", text)

        # Несколько запятых/пробелов → одна
        text = _re.sub(r"[,]{2,}", ",", text)
        text = _re.sub(r"\s{2,}", " ", text)

        return text.strip()

    @staticmethod
    def _fix_latin(text: str) -> str:
        """Заменяет единицы измерения и транслитерирует латиницу"""
        import re as _re

        # Диапазоны температур: "-5..-1" → "от минус 5 до минус 1"
        #                        "-3..7"  → "от минус 3 до 7"
        #                        "0..5"   → "от 0 до 5"
        def _repl_range(m):
            a, b = m.group(1), m.group(2)
            def _fmt(n):
                n = n.strip()
                if n.startswith("-"):
                    return "минус " + n[1:]
                return n
            return f"от {_fmt(a)} до {_fmt(b)}"
        text = _re.sub(r'(-?\d+)\.\.(-?\d+)', _repl_range, text)

        # Одиночный минус перед числом в начале или после пробела/запятой
        def _repl_minus(m):
            return " минус " + m.group(1)
        text = _re.sub(r'(?<![\d\w])-(?=\d)', lambda m: " минус ", text)

        # °C → "X градусов"
        def _repl_deg(m):
            return m.group(1) + " градусов"
        def _repl_kmh(m):
            return m.group(1) + " километров в час"
        def _repl_pct(m):
            return m.group(1) + " процентов"

        text = _re.sub(r'(-?\d+)\s*°[Cc]', _repl_deg, text)
        text = _re.sub(r'(-?\d+)\s*°',     _repl_deg, text)
        text = _re.sub(r'(\d+)\s*км/ч',    _repl_kmh, text)
        text = _re.sub(r'(\d+)\s*%',       _repl_pct, text)

        # Двойные пробелы после замен
        text = _re.sub(r' {2,}', ' ', text)

        # Транслитерация латинских слов
        tmap = {
            'a':'а','b':'б','c':'к','d':'д','e':'е','f':'ф',
            'g':'г','h':'х','i':'и','j':'дж','k':'к','l':'л',
            'm':'м','n':'н','o':'о','p':'п','q':'к','r':'р',
            's':'с','t':'т','u':'у','v':'в','w':'в','x':'кс',
            'y':'й','z':'з'
        }
        result = []
        for word in text.split():
            clean = _re.sub(r'[^a-zA-Z\-]', '', word).lower()
            if clean and _re.match(r'^[a-z\-]+$', clean):
                ru = TTS._EN_TO_RU.get(clean)
                result.append(ru if ru else ''.join(tmap.get(c, c) for c in clean))
            else:
                result.append(word)
        return ' '.join(result)

    def _speak_edge(self, text: str, done_cb=None):
        self._busy = True
        text = self._strip_emoji(text)
        text = self._fix_latin(text)
        with self._lock:
            try:
                import edge_tts, asyncio, tempfile, pygame
                # Создаём временный mp3
                tmp = tempfile.NamedTemporaryFile(
                    suffix=".mp3", delete=False)
                tmp.close()

                async def _gen():
                    comm = edge_tts.Communicate(text, self._voice,
                                                 rate="+5%", volume="+10%")
                    await comm.save(tmp.name)

                asyncio.run(_gen())

                # Воспроизводим через pygame
                pygame.mixer.music.load(tmp.name)
                pygame.mixer.music.play()
                while pygame.mixer.music.get_busy():
                    time.sleep(0.05)
                pygame.mixer.music.unload()
                try:
                    os.unlink(tmp.name)
                except:
                    pass
                print(f"[TTS] edge-tts: '{text[:40]}...'")
            except Exception as e:
                print(f"[TTS] edge-tts ошибка: {e}")
                # Fallback на pyttsx3
                if self._pyttsx_engine:
                    self._speak_pyttsx_sync(text)
        self._busy = False
        if done_cb: done_cb()

    def _speak_pyttsx(self, text: str, done_cb=None):
        self._busy = True
        with self._lock:
            self._speak_pyttsx_sync(text)
        self._busy = False
        if done_cb: done_cb()

    def _speak_pyttsx_sync(self, text: str):
        text = self._strip_emoji(text)
        text = self._fix_latin(text)
        try:
            self._pyttsx_engine.say(text)
            self._pyttsx_engine.runAndWait()
        except Exception as e:
            print(f"[TTS] pyttsx3 ошибка: {e}")


