# МИКРОФОН + РАСПОЗНАВАНИЕ
# ══════════════════════════════════════════════════════════
class MicListener:
    def __init__(self, config: dict):
        self.config = config
        self.sr = None
        self.recognizer = None
        self.mic = None
        self.has_audio = False
        self._stop_fn = None
        self._init()

    def _init(self):
        try:
            import pyaudio
        except ImportError:
            print("[Mic] pyaudio не установлен!")
            return

        try:
            import speech_recognition as sr
            self.sr = sr
            r = sr.Recognizer()
            # ── Порог энергии ─────────────────────────────
            # 300 = игнорирует тихие шорохи/фон, но слышит нормальную речь
            # dynamic=True — сам подстраивается под уровень шума в комнате
            # damping=0.25 — плавная подстройка (0.15 слишком дёргано)
            r.energy_threshold = 300
            r.dynamic_energy_threshold = True
            r.dynamic_energy_adjustment_damping = 0.25
            r.dynamic_energy_ratio = 1.5      # порог = 1.5x от фонового шума

            # ── Паузы и фразы ──────────────────────────────
            # pause_threshold=1.0 — ждёт 1 сек тишины прежде чем считать фразу законченной
            # это убирает обрывы в середине фразы
            r.pause_threshold = 1.0
            r.non_speaking_duration = 0.6     # минимум тишины до/после фразы
            r.phrase_threshold = 0.3          # минимальная длина фразы чтобы не считать шум
            r.operation_timeout = None
            self.recognizer = r
        except ImportError:
            print("[Mic] speech_recognition не установлен!")
            return

        self._pick_best_mic()
        self.has_audio = (self.mic is not None)

    def _pick_best_mic(self):
        sr = self.sr

        # Если задан вручную — используем его
        saved_idx = self.config.get("mic_index")
        if saved_idx is not None:
            try:
                m = sr.Microphone(device_index=int(saved_idx))
                if self._test_mic(m):
                    self.mic = m
                    print(f"[Mic] Сохранённый индекс {saved_idx} OK")
                    return
            except Exception as e:
                print(f"[Mic] Сохранённый {saved_idx} недоступен: {e}")

        print(f"[Mic] Найдено устройств: {len(sr.Microphone.list_microphone_names())}")

        # ШАГ 1: Берём системный микрофон по умолчанию через pyaudio
        # Это именно тот, что стоит в настройках Windows
        try:
            import pyaudio
            p = pyaudio.PyAudio()
            default_idx = p.get_default_input_device_info()["index"]
            default_name = p.get_device_info_by_index(default_idx)["name"]
            p.terminate()
            m = sr.Microphone(device_index=default_idx)
            if self._test_mic(m):
                self.mic = m
                print(f"[Mic] Системный по умолчанию: [{default_idx}] {default_name}")
                return
        except Exception as e:
            print(f"[Mic] Системный по умолчанию недоступен: {e}")

        # ШАГ 2: Перебираем все входные устройства
        try:
            import pyaudio
            p = pyaudio.PyAudio()
            skip_kw = ["output","вывод","speaker","динамик","stereo mix",
                       "стерео микш","spdif","virtual","виртуальный",
                       "nvidia","zowie","t238y","lcd","mapper - output",
                       "realtek digital","линейный выход","лин. вых"]
            prio_kw = ["fifine","blue","rode","hyperx","samson","usb",
                       "микрофон","microphone","headset","гарнитур","gaming"]
            candidates = []
            for i in range(p.get_device_count()):
                try:
                    info = p.get_device_info_by_index(i)
                    if info["maxInputChannels"] <= 0:
                        continue
                    nl = info["name"].lower()
                    if any(k in nl for k in skip_kw):
                        continue
                    score = sum(1 for k in prio_kw if k in nl)
                    candidates.append((score, i, info["name"]))
                except:
                    continue
            p.terminate()
            candidates.sort(key=lambda x: (-x[0], x[1]))
            for score, idx, name in candidates:
                m = sr.Microphone(device_index=idx)
                if self._test_mic(m):
                    self.mic = m
                    print(f"[Mic] Выбран: [{idx}] {name}")
                    return
        except Exception as e:
            print(f"[Mic] Перебор устройств ошибка: {e}")

        # ШАГ 3: Абсолютный fallback
        try:
            self.mic = sr.Microphone()
            print("[Mic] Fallback: sr.Microphone() без индекса")
        except Exception as e:
            print(f"[Mic] Полная ошибка: {e}")

    def _test_mic(self, mic) -> bool:
        """Проверяет что микрофон реально открывается"""
        try:
            pa = mic.audio.__class__
        except:
            pass
        try:
            import pyaudio
            p = pyaudio.PyAudio()
            idx = mic.device_index
            if idx is None:
                idx = p.get_default_input_device_info()["index"]
            info = p.get_device_info_by_index(idx)
            p.terminate()
            # Должен быть входной канал
            if info.get("maxInputChannels", 0) > 0:
                return True
            return False
        except Exception as e:
            return False

    # ── Vosk модель (грузится один раз) ──────────────────
    _vosk_model = None
    _vosk_ok    = False

    @classmethod
    def _load_vosk(cls):
        if cls._vosk_ok:
            return True
        try:
            from vosk import Model, KaldiRecognizer
            import os
            # Ищем модель в папке scarlett
            here = os.path.dirname(os.path.abspath(
                sys.executable if getattr(sys,'frozen',False) else __file__))
            model_dirs = [
                os.path.join(here, "vosk-model-ru"),
                os.path.join(here, "vosk-model-small-ru"),
                os.path.join(os.path.expanduser("~"), "vosk-model-ru"),
            ]
            model_path = next((p for p in model_dirs if os.path.isdir(p)), None)
            if not model_path:
                print("[Vosk] Модель не найдена — скачай vosk-model-small-ru")
                print("[Vosk] https://alphacephei.com/vosk/models")
                return False
            cls._vosk_model = Model(model_path)
            cls._vosk_ok = True
            print(f"[Vosk] Модель загружена: {model_path}")
            return True
        except ImportError:
            print("[Vosk] vosk не установлен, используем Google STT")
            return False
        except Exception as e:
            print(f"[Vosk] Ошибка загрузки: {e}")
            return False

    def start(self, callback):
        if not self.recognizer or not self.mic:
            print("[Mic] Микрофон не инициализирован")
            return False

        # Google STT точнее для русского → основной при наличии интернета
        # Vosk → только если нет интернета
        _inet = self._check_internet()
        if _inet:
            print("[Mic] Режим: Google STT (онлайн, точный)")
            self._start_google(callback)
        else:
            vosk_ready = self._load_vosk()
            if vosk_ready:
                print("[Mic] Режим: Vosk (оффлайн, нет интернета)")
                self._start_vosk(callback)
            else:
                print("[Mic] Нет ни интернета, ни Vosk — микрофон недоступен")
                return False
        return True

    @staticmethod
    def _check_internet() -> bool:
        try:
            import socket
            socket.setdefaulttimeout(2)
            s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            s.connect(("8.8.8.8", 53))
            s.close()
            return True
        except:
            return False

    def _start_vosk(self, callback):
        """Vosk: непрерывное распознавание через поток аудио"""
        import threading, json as _json
        from vosk import KaldiRecognizer

        def _vosk_thread():
            try:
                import pyaudio
                rec = KaldiRecognizer(self._vosk_model, 16000)
                rec.SetWords(True)
                p = pyaudio.PyAudio()
                idx = self.mic.device_index
                if idx is None:
                    idx = p.get_default_input_device_info()["index"]
                stream = p.open(
                    format=pyaudio.paInt16,
                    channels=1,
                    rate=16000,
                    input=True,
                    input_device_index=idx,
                    frames_per_buffer=4096,
                )
                print("[Vosk] Поток запущен")
                while self._vosk_running:
                    data = stream.read(4096, exception_on_overflow=False)
                    if rec.AcceptWaveform(data):
                        res = _json.loads(rec.Result())
                        text = res.get("text","").strip()
                        # Фильтр мусора: меньше 3 символов или только одна буква = шум
                        if text and len(text) >= 3 and len(text.split()) >= 1:
                            # Игнорируем явно случайные звуки
                            if text not in ("а","э","м","ну","да","не","ой","ай","ей","хм"):
                                print(f"[VOICE/Vosk] {text}")
                                callback(text)
                            else:
                                print(f"[VOICE/Vosk] filtered noise: '{text}'"
                                      )
                stream.stop_stream()
                stream.close()
                p.terminate()
            except Exception as e:
                print(f"[Vosk] Поток упал: {e}")
                # Fallback на Google
                self._start_google(callback)

        self._vosk_running = True
        t = threading.Thread(target=_vosk_thread, daemon=True)
        t.start()

    def _start_google(self, callback):
        """Google STT fallback"""
        _noise = {"а","э","м","ну","да","не","ой","ай","ей","хм","ах","эм","мм"}
        def _handler(_, audio):
            try:
                text = self.recognizer.recognize_google(audio, language="ru-RU")
                text = text.strip()
                # Фильтр мусора — короткие случайные звуки
                if text and len(text) >= 3 and text.lower() not in _noise:
                    print(f"[VOICE/Google] {text}")
                    callback(text)
                elif text:
                    print(f"[VOICE/Google] filtered: '{text}'"
                          )
            except self.sr.UnknownValueError:
                pass
            except self.sr.RequestError as e:
                print(f"[Mic] Google API недоступен: {e}")
            except Exception as e:
                print(f"[Mic] Ошибка: {e}")
        try:
            self._stop_fn = self.recognizer.listen_in_background(
                self.mic, _handler, phrase_time_limit=12)
            print("[Mic] Google STT запущен")
        except Exception as e:
            print(f"[Mic] Ошибка запуска Google: {e}")

    def stop(self):
        try:
            if self._stop_fn:
                self._stop_fn(wait_for_stop=False)
        except:
            pass


