# ─────────────────────────────────────────────────────────
# Апгрейд 1: Долгосрочная векторная память (ChromaDB)
# ─────────────────────────────────────────────────────────
class VectorMemory:
    """
    Локальная векторная БД для долгосрочной памяти Scarlett.
    Использует ChromaDB + sentence-transformers (all-MiniLM-L6-v2).
    Работает полностью оффлайн, модель embeddings скачивается один раз.
    Graceful degradation: если ChromaDB не установлена — тихо отключается.
    """

    def __init__(self, config: dict):
        self.config  = config
        self._client = None
        self._col    = None
        self._embed  = None
        self._ok     = False
        threading.Thread(target=self._init, daemon=True).start()

    def _init(self):
        """Инициализация в фоновом потоке — не блокирует запуск Scarlett"""
        try:
            import chromadb
            from chromadb.config import Settings as CSettings

            db_path = os.path.join(os.path.expanduser("~"), ".scarlett_memory")
            os.makedirs(db_path, exist_ok=True)

            self._client = chromadb.PersistentClient(
                path=db_path,
                settings=CSettings(anonymized_telemetry=False))
            self._col = self._client.get_or_create_collection(
                name="scarlett_memory",
                metadata={"hnsw:space": "cosine"})
            print(f"[Memory] ChromaDB OK — {self._col.count()} воспоминаний")
        except ImportError:
            print("[Memory] chromadb не установлен → pip install chromadb")
            print("[Memory] Долгосрочная память отключена (работает краткосрочная)")
            return
        except Exception as e:
            print(f"[Memory] ChromaDB ошибка: {e}")
            return

        try:
            from sentence_transformers import SentenceTransformer
            self._embed = SentenceTransformer("all-MiniLM-L6-v2")
            print("[Memory] sentence-transformers OK")
            self._ok = True
        except ImportError:
            print("[Memory] sentence-transformers не установлен → pip install sentence-transformers")
            # Fallback: простой TF-IDF через sklearn если доступен
            try:
                from sklearn.feature_extraction.text import TfidfVectorizer
                self._embed = None   # флаг: используем TF-IDF
                self._ok = True
                print("[Memory] Fallback: TF-IDF embeddings (sklearn)")
            except ImportError:
                print("[Memory] sklearn тоже нет — память отключена")
        except Exception as e:
            print(f"[Memory] sentence-transformers ошибка: {e}")

    def _get_embedding(self, text: str) -> list:
        """Возвращает вектор для текста"""
        if self._embed is not None:
            # sentence-transformers
            vec = self._embed.encode([text])[0]
            return vec.tolist()
        else:
            # Простой fallback — bag of words (менее точный но работает)
            import hashlib, struct
            # Детерминированный псевдо-вектор на основе хэшей слов
            words = text.lower().split()
            vec = [0.0] * 384
            for word in words:
                h = int(hashlib.md5(word.encode()).hexdigest(), 16)
                idx = h % 384
                vec[idx] += 1.0
            # Нормализуем
            norm = (sum(x*x for x in vec) ** 0.5) or 1.0
            return [x/norm for x in vec]

    def add(self, text: str):
        """Добавляет фразу пользователя в долгосрочную память"""
        if not self._ok or not self._col:
            return
        # Не запоминаем слишком короткие фразы (< 5 слов)
        if len(text.split()) < 5:
            return
        # Не запоминаем системные команды
        skip_prefixes = ["открой","запусти","включи","выключи","тише","громче",
                         "который","сколько","скажи","покажи"]
        if any(text.lower().startswith(p) for p in skip_prefixes):
            return
        try:
            emb = self._get_embedding(text)
            doc_id = f"mem_{int(time.time()*1000)}"
            self._col.add(
                documents=[text],
                embeddings=[emb],
                ids=[doc_id],
                metadatas=[{"ts": int(time.time())}]
            )
            # Ограничиваем размер: максимум 500 воспоминаний
            count = self._col.count()
            if count > 500:
                # Удаляем самые старые
                oldest = self._col.get(limit=50,
                                        include=["metadatas"],
                                        where={"ts": {"$lt": int(time.time()) - 86400*30}})
                if oldest["ids"]:
                    self._col.delete(ids=oldest["ids"][:25])
        except Exception as e:
            print(f"[Memory] add error: {e}")

    def search(self, query: str, top_k: int = 3) -> list:
        """Поиск релевантных воспоминаний по смысловой близости"""
        if not self._ok or not self._col or self._col.count() == 0:
            return []
        try:
            emb = self._get_embedding(query)
            results = self._col.query(
                query_embeddings=[emb],
                n_results=min(top_k, self._col.count()),
                include=["documents", "distances"]
            )
            # Фильтруем по порогу схожести (cosine distance < 0.5 = похоже)
            docs  = results.get("documents", [[]])[0]
            dists = results.get("distances",  [[]])[0]
            relevant = [d for d, dist in zip(docs, dists) if dist < 0.5]
            return relevant
        except Exception as e:
            print(f"[Memory] search error: {e}")
            return []

    def stats(self) -> str:
        """Статистика памяти для UI"""
        if not self._ok:
            return "векторная память отключена (установи chromadb)"
        try:
            return f"{self._col.count()} воспоминаний в ChromaDB"
        except Exception:
            return "память недоступна"


# ─────────────────────────────────────────────────────────
# Апгрейд 2: Параллельное выполнение команд
# ─────────────────────────────────────────────────────────
class _CommandExecutor:
    """
    Разбирает фразу с несколькими командами и выполняет их параллельно.
    Примеры:
      "открой хром и включи музыку"  → запускает оба параллельно
      "тише и открой телеграм"       → оба одновременно
    Graceful degradation: если не удалось распознать — возвращает None,
    Brain.process() продолжает стандартную обработку.
    """

    # Разделители нескольких команд
    _SPLIT_WORDS = [" и ", " да и ", " а также ", " плюс ", " + "]

    # Слова-признаки команды (нужны хотя бы в одной части)
    _CMD_VERBS = {
        "открой","запусти","включи","выключи","закрой","найди","погугли",
        "тише","громче","пауза","стоп","следующий","предыдущий","играй",
        "установи","поставь","убавь","прибавь",
    }

    def try_parallel(self, normalized_text: str, brain, name: str):
        """
        Пробует разбить текст на несколько команд.
        Возвращает объединённый ответ или None.
        """
        t = normalized_text.strip()

        # Ищем разделитель
        parts = None
        for sep in self._SPLIT_WORDS:
            if sep in t:
                p = [x.strip() for x in t.split(sep) if x.strip()]
                if len(p) >= 2:
                    parts = p
                    break

        if not parts:
            return None

        # Проверяем что каждая часть похожа на команду
        has_cmd = any(
            any(v in part for v in self._CMD_VERBS)
            for part in parts
        )
        if not has_cmd:
            return None

        # Запускаем параллельно через ThreadPoolExecutor
        from concurrent.futures import ThreadPoolExecutor, as_completed

        def _exec_part(part_text: str):
            try:
                resp, _ = brain.process(part_text)
                return resp
            except Exception as e:
                return f"ошибка: {e}"

        results = []
        with ThreadPoolExecutor(max_workers=len(parts)) as ex:
            futures = {ex.submit(_exec_part, p): p for p in parts}
            for fut in as_completed(futures):
                try:
                    results.append(fut.result(timeout=10))
                except Exception:
                    pass

        if not results:
            return None

        # Объединяем ответы
        combined = " | ".join(r for r in results if r)
        return combined if combined else None


# ─────────────────────────────────────────────────────────
# Апгрейд 3: Системный контекст в реальном времени
# ─────────────────────────────────────────────────────────
class SystemContext:
    """
    Собирает контекст системы для обогащения промпта AI.
    Узнаёт: активное окно, запущенные приложения, текущая музыка, время суток.
    Graceful degradation: каждый источник данных обёрнут в try/except.
    Кэширует данные 5 секунд — не нагружает систему.
    """

    def __init__(self):
        self._cache_ts  = 0
        self._cache_val = ""
        self._TTL       = 5   # секунд

    def get(self) -> str:
        """Возвращает строку контекста для системного промпта"""
        now = time.time()
        if now - self._cache_ts < self._TTL:
            return self._cache_val
        self._cache_ts  = now
        self._cache_val = self._collect()
        return self._cache_val

    def _collect(self) -> str:
        parts = []

        # ── Время суток ───────────────────────────────────
        h = datetime.datetime.now().hour
        if 5 <= h < 12:   parts.append("утро")
        elif 12 <= h < 17: parts.append("день")
        elif 17 <= h < 23: parts.append("вечер")
        else:              parts.append("ночь")

        # ── Активное окно (win32gui) ───────────────────────
        try:
            import win32gui, win32process
            hwnd  = win32gui.GetForegroundWindow()
            title = win32gui.GetWindowText(hwnd)
            if title:
                # Убираем длинные пути, оставляем суть
                title = title.split(" - ")[-1].strip()
                title = title[:40]
                if title:
                    parts.append(f"активное окно: {title}")
        except Exception:
            pass

        # ── Запущенные приложения (psutil) ────────────────
        try:
            interesting = {
                "chrome.exe":   "Chrome",
                "msedge.exe":   "Edge",
                "firefox.exe":  "Firefox",
                "telegram.exe": "Telegram",
                "discord.exe":  "Discord",
                "steam.exe":    "Steam",
                "spotify.exe":  "Spotify",
                "code.exe":     "VS Code",
                "obs64.exe":    "OBS",
                "obs.exe":      "OBS",
                "vlc.exe":      "VLC",
                "pycharm64.exe":"PyCharm",
                "devenv.exe":   "Visual Studio",
                "photoshop.exe":"Photoshop",
                "figma.exe":    "Figma",
            }
            running = []
            for proc in psutil.process_iter(["name"]):
                pn = proc.info["name"].lower()
                if pn in interesting:
                    running.append(interesting[pn])
            if running:
                parts.append(f"открыто: {', '.join(running[:5])}")
        except Exception:
            pass

        # ── Уровень громкости ─────────────────────────────
        # (не берём — это может вызвать рекурсию через VolumeControl)

        # ── Текущая музыка (Windows Media API) ───────────
        try:
            import subprocess, json as _j
            # PowerShell запрос к Windows Media — легковесный
            ps_cmd = (
                "Add-Type -AssemblyName System.Runtime.WindowsRuntime; "
                "$sm = [Windows.Media.Control.GlobalSystemMediaTransportControlsSessionManager"
                "::RequestAsync().GetAwaiter().GetResult(); "
                "$sess = $sm.GetCurrentSession(); "
                "if ($sess) { $info = $sess.TryGetMediaPropertiesAsync().GetAwaiter().GetResult(); "
                "Write-Output ($info.Title + ' — ' + $info.Artist) } "
                "else { Write-Output '' }"
            )
            result = subprocess.run(
                ["powershell", "-NoProfile", "-Command", ps_cmd],
                capture_output=True, text=True, timeout=2,
                creationflags=subprocess.CREATE_NO_WINDOW)
            track = result.stdout.strip()
            if track and len(track) > 2 and " — " in track:
                parts.append(f"играет: {track[:50]}")
        except Exception:
            pass

        return ", ".join(parts)


# ─────────────────────────────────────────────────────────
# Апгрейд 4: LLM Tool Calling
# ─────────────────────────────────────────────────────────
class LLMToolCaller:
    """
    Вместо 500+ строк if/elif — отправляем запрос в LLM с набором tools.
    LLM сам понимает намерение и возвращает JSON с вызовом инструмента.
    Работает только если есть API ключ (Groq/Mistral — бесплатные).
    Graceful degradation: если LLM недоступен → возвращает None,
    Brain.process() продолжает стандартную обработку.
    """

    # Описание инструментов для LLM
    TOOLS = [
        {
            "type": "function",
            "function": {
                "name": "open_app",
                "description": "Открыть или запустить приложение, игру или сайт на Windows",
                "parameters": {
                    "type": "object",
                    "properties": {
                        "app_name": {"type": "string",
                                     "description": "Название приложения, игры или сайта"}
                    },
                    "required": ["app_name"]
                }
            }
        },
        {
            "type": "function",
            "function": {
                "name": "set_volume",
                "description": "Установить громкость системы на конкретный процент",
                "parameters": {
                    "type": "object",
                    "properties": {
                        "level": {"type": "integer",
                                  "description": "Уровень громкости от 0 до 100"}
                    },
                    "required": ["level"]
                }
            }
        },
        {
            "type": "function",
            "function": {
                "name": "search_web",
                "description": "Найти что-то в интернете через браузер",
                "parameters": {
                    "type": "object",
                    "properties": {
                        "query": {"type": "string",
                                  "description": "Поисковый запрос"}
                    },
                    "required": ["query"]
                }
            }
        },
        {
            "type": "function",
            "function": {
                "name": "set_timer",
                "description": "Поставить таймер или напоминание",
                "parameters": {
                    "type": "object",
                    "properties": {
                        "seconds":  {"type": "integer",
                                     "description": "Время в секундах"},
                        "label":    {"type": "string",
                                     "description": "Что напомнить"}
                    },
                    "required": ["seconds"]
                }
            }
        },
        {
            "type": "function",
            "function": {
                "name": "media_control",
                "description": "Управление воспроизведением музыки",
                "parameters": {
                    "type": "object",
                    "properties": {
                        "action": {
                            "type": "string",
                            "enum": ["play", "pause", "next", "prev", "shuffle"],
                            "description": "Действие"
                        }
                    },
                    "required": ["action"]
                }
            }
        },
    ]

    def __init__(self, brain):
        self._brain = brain
        self._last_use   = 0
        self._cooldown   = 0.5   # минимум между вызовами (сек)
        self._fail_count = 0     # счётчик неудач
        self._max_fails  = 3     # после 3 неудач — отключаемся до перезапуска

    def try_call(self, text: str, name: str):
        """
        Пробует распознать команду через LLM tool calling.
        Возвращает строку-ответ или None.
        """
        # Throttle
        now = time.time()
        if now - self._last_use < self._cooldown:
            return None
        if self._fail_count >= self._max_fails:
            return None

        # Не вызываем tool calling для явно неоднозначных вопросов
        # (оставляем обычному AI-роутеру)
        SKIP_WORDS = ["почему","расскажи","объясни","что такое","как ты",
                      "кто ты","анекдот","шутку","думаешь","считаешь"]
        t = text.lower()
        if any(w in t for w in SKIP_WORDS):
            return None

        cfg    = self._brain.config
        result = None

        # Пробуем Groq (самый быстрый, бесплатный)
        if cfg.get("groq_key"):
            result = self._call_groq(text, name, cfg["groq_key"])
        # Или Mistral (работает в РФ без VPN)
        if result is None and cfg.get("mistral_key"):
            result = self._call_mistral(text, name, cfg["mistral_key"])

        self._last_use = time.time()
        return result

    def _build_messages(self, text: str, name: str) -> list:
        return [
            {
                "role": "system",
                "content": (
                    f"Ты голосовой ассистент Scarlett. Пользователь: {name}. "
                    f"Если запрос является командой — вызови подходящий tool. "
                    f"Если это вопрос или разговор — НЕ вызывай tool, ответь None."
                )
            },
            {"role": "user", "content": text}
        ]

    def _execute_tool(self, name_: str, args: dict) -> str:
        """Выполняет инструмент и возвращает ответ"""
        brain = self._brain
        try:
            if name_ == "open_app":
                return brain.launcher.launch(args.get("app_name", ""))

            elif name_ == "set_volume":
                lvl = max(0, min(100, int(args.get("level", 50))))
                brain.vol.set(lvl)
                return f"Громкость установлена на {lvl}%"

            elif name_ == "search_web":
                q = args.get("query", "")
                brain._open_default_browser(
                    "https://www.google.com/search?q=" +
                    urllib.parse.quote_plus(q))
                return f"Ищу: {q}"

            elif name_ == "set_timer":
                secs  = int(args.get("seconds", 60))
                label = args.get("label", "таймер")
                fmt   = brain._fmt_seconds(secs)
                def _fire(lbl):
                    try: brain._fire_reminder_cb(f"Время! {lbl}")
                    except Exception: pass
                brain._set_reminder(secs, label, _fire)
                return f"Таймер на {fmt} установлен"

            elif name_ == "media_control":
                action = args.get("action", "pause")
                keys = {
                    "play":    0xB3, "pause": 0xB3,
                    "next":    0xB0, "prev":  0xB1,
                    "shuffle": None
                }
                vk = keys.get(action)
                if vk:
                    brain._media_key(vk)
                elif action == "shuffle":
                    ctypes.windll.user32.keybd_event(0x11, 0, 0, 0)
                    ctypes.windll.user32.keybd_event(0x53, 0, 0, 0)
                    ctypes.windll.user32.keybd_event(0x53, 0, 2, 0)
                    ctypes.windll.user32.keybd_event(0x11, 0, 2, 0)
                labels = {"play":"Воспроизвожу","pause":"Пауза",
                          "next":"Следующий трек","prev":"Предыдущий трек",
                          "shuffle":"Shuffle включён"}
                return labels.get(action, "Готово")

        except Exception as e:
            print(f"[ToolCall] execute error {name_}: {e}")
        return None

    def _parse_tool_call(self, data: dict):
        """Извлекает tool call из ответа LLM"""
        import json as _j
        try:
            choices = data.get("choices", [])
            if not choices:
                return None, None
            msg = choices[0].get("message", {})
            tool_calls = msg.get("tool_calls", [])
            if not tool_calls:
                return None, None
            tc   = tool_calls[0]
            fn   = tc.get("function", {})
            name_ = fn.get("name", "")
            args  = fn.get("arguments", "{}")
            if isinstance(args, str):
                args = _j.loads(args)
            return name_, args
        except Exception as e:
            print(f"[ToolCall] parse error: {e}")
            return None, None

    def _call_groq(self, text: str, name: str, api_key: str):
        import urllib.request, json as _j
        try:
            payload = _j.dumps({
                "model":    "llama-3.3-70b-versatile",
                "messages": self._build_messages(text, name),
                "tools":    self.TOOLS,
                "tool_choice": "auto",
                "max_tokens": 150,
                "temperature": 0,
            }).encode("utf-8")
            req = urllib.request.Request(
                "https://api.groq.com/openai/v1/chat/completions",
                data=payload,
                headers={"Content-Type": "application/json",
                         "Authorization": f"Bearer {api_key}"}
            )
            with urllib.request.urlopen(req, timeout=6) as resp:
                data = _j.loads(resp.read())
            tool_name, args = self._parse_tool_call(data)
            if tool_name:
                result = self._execute_tool(tool_name, args)
                if result:
                    print(f"[ToolCall/Groq] {tool_name}({args}) → {result[:50]}")
                    self._fail_count = 0
                    return result
        except Exception as e:
            print(f"[ToolCall/Groq] error: {e}")
            self._fail_count += 1
        return None

    def _call_mistral(self, text: str, name: str, api_key: str):
        import urllib.request, json as _j
        try:
            payload = _j.dumps({
                "model":    "mistral-small-latest",
                "messages": self._build_messages(text, name),
                "tools":    self.TOOLS,
                "tool_choice": "auto",
                "max_tokens": 150,
                "temperature": 0,
            }).encode("utf-8")
            req = urllib.request.Request(
                "https://api.mistral.ai/v1/chat/completions",
                data=payload,
                headers={"Content-Type": "application/json",
                         "Authorization": f"Bearer {api_key}"}
            )
            with urllib.request.urlopen(req, timeout=8) as resp:
                data = _j.loads(resp.read())
            tool_name, args = self._parse_tool_call(data)
            if tool_name:
                result = self._execute_tool(tool_name, args)
                if result:
                    print(f"[ToolCall/Mistral] {tool_name}({args}) → {result[:50]}")
                    self._fail_count = 0
                    return result
        except Exception as e:
            print(f"[ToolCall/Mistral] error: {e}")
            self._fail_count += 1
        return None


# ══════════════════════════════════════════════════════════
# МОЗГ — обработка команд
# ══════════════════════════════════════════════════════════
class Brain:
    def __init__(self, config: dict, vol: VolumeControl, launcher: AppLauncher):
        self.config = config
        self.vol = vol
        self.launcher = launcher
        self.memory = []  # (роль, текст) — краткосрочная память сессии
        self._timers = []  # активные таймеры: {id, label, thread}
        self._timer_id = 0
        self._fire_reminder_cb = lambda msg: None  # переопределяется в App

        # ── Апгрейд 1: Векторная память (ChromaDB) ───────────────────────
        self._vm = VectorMemory(config)   # lazy init — не блокирует старт

        # ── Апгрейд 2: Параллельный исполнитель команд ───────────────────
        self._executor = _CommandExecutor()

        # ── Апгрейд 3: Системный контекст ────────────────────────────────
        self._sys_ctx = SystemContext()

        # ── Апгрейд 4: LLM Tool Caller ───────────────────────────────────
        self._tool_caller = LLMToolCaller(self)

    def remember(self, role, text):
        self.memory.append((role, text))
        if len(self.memory) > 20:
            self.memory = self.memory[-20:]
        # Сохраняем в векторную память (только реплики пользователя)
        if role == "user" and self.config.get("vector_memory_enabled", True):
            self._vm.add(text)
        # Персистентная история в конфиге (последние 10 обменов)
        self.config["chat_history"] = [list(m) for m in self.memory[-10:]]
        try:
            save_config(self.config)
        except Exception:
            pass

