        if any(w in t for w in weather_words):
            city = self.config.get("city", "Москва")
            # Пробуем разные паттерны поиска города
            patterns = [
                # "погода в Белгороде", "погоду в Москве"
                r'погод\w*\s+(?:в\s+|во\s+|для\s+|по\s+)([А-ЯЁ][а-яёА-ЯЁ\-]{2,20})',
                # "в Белгороде погода"
                r'(?:^|\s)(?:в|во)\s+([А-ЯЁ][а-яёА-ЯЁ\-]{2,20})\s+погод',
                # "температура в Сочи"
                r'(?:температур|прогноз|градус)\w*\s+(?:в\s+|для\s+)?([А-ЯЁ][а-яёА-ЯЁ\-]{2,20})',
            ]
            for pat in patterns:
                m2 = re.search(pat, text)
                if m2 and m2.group(1).strip():
                    raw = m2.group(1).strip()
                    # Убираем возможный мусор в конце
                    raw = re.sub(r'(сейчас|сегодня|завтра|там|ли|пожалуйста)$', '',
                                  raw, flags=re.I).strip()
                    if len(raw) > 2:
                        city = raw
