        if any(w in t for w in ["перемешай","рандом","shuffle","случайный порядок",
                                  "случайный трек","перемешать"]):
            # Ctrl+S в большинстве плееров = shuffle
            import ctypes as _ct
            _ct.windll.user32.keybd_event(0x11, 0, 0, 0)  # Ctrl down
            _ct.windll.user32.keybd_event(0x53, 0, 0, 0)  # S down
            _ct.windll.user32.keybd_event(0x53, 0, 2, 0)  # S up
            _ct.windll.user32.keybd_event(0x11, 0, 2, 0)  # Ctrl up
            return reply("Shuffle включён")

        if any(w in t for w in ["анекдот","пошути","шутку","рассмеши","смешное",
                                  "посмеёмся","рассмеши меня","что-нибудь смешное",
                                  "расскажи что нибудь смешное","развесели",
                                  "расскажи анекдот","смешной","хочу смеяться"]):
            return reply(random.choice(JOKES))

        # ── Математика ────────────────────────────────────
        m = re.search(r'(?:посчитай|вычисли|сколько будет|сколько это)\s+(.+)', t)
        if m:
            expr = m.group(1)
            expr = (expr.replace("плюс","+").replace("минус","-")
                       .replace("умножить на","*").replace("умножить","*")
                       .replace("разделить на","/").replace("разделить","/")
                       .replace("в степени","**").replace("степень","**"))
            try:
                clean = re.sub(r'[^0-9+\-*/().\s]', '', expr)
                result = eval(clean)
                return reply(f"{m.group(1)} = {result}")
            except:
                return reply(f"Не смогла посчитать «{m.group(1)}»")

        # ── Имя ───────────────────────────────────────────
        if any(w in t for w in ["как меня зовут", "моё имя", "мое имя", "моё имя"]):
            return reply(f"Тебя зовут {name}.")

