# ГЛАВНОЕ ОКНО
# ══════════════════════════════════════════════════════════
class App:
    WAKE_WORDS = ["скарлетт", "scarlett", "эй скарлетт", "привет скарлетт"]

    def __init__(self, autostart=False):
        self.config = load_config()
        self.vol = VolumeControl()
        self.launcher = AppLauncher()
        self.brain = Brain(self.config, self.vol, self.launcher)
        self.tts = TTS()
        self.mic = MicListener(self.config)

        # Callback для таймеров — показывает сообщение в чате и озвучивает
        def _on_timer_fire(msg: str):
            def _ui():
                # Показываем в чате с префиксом ⏰
                self._add_msg("⏰ " + msg, user=False)
                # Озвучиваем (без иконки — TTS не читает эмодзи)
                self.tts.speak(msg)
                # Показываем окно если свёрнуто
                try:
                    self.root.deiconify()
                    self.root.lift()
                    self.root.focus_force()
                except: pass
                # Мигаем статусом
                def _blink(n=0):
                    if n >= 6: 
                        self._set_status("Активна", C["ok"])
                        return
                    col = C["accent"] if n % 2 == 0 else C["accent3"]
                    self._set_status("⏰ ВРЕМЯ!", col)
                    self.root.after(400, lambda: _blink(n+1))
                _blink()
            self.root.after(0, _ui)
        self.brain._fire_reminder_cb = _on_timer_fire
        self.q = queue.Queue()
        self.sleeping = False
        self.frame = 0
        self._processing = False
        self._autostart = autostart   # запущена из автозагрузки?

        self._build_ui()  # root создаётся здесь

        # TrayIcon создаём ПОСЛЕ _build_ui (нужен self.root)
        self.tray = TrayIcon(self.root, self._wake_up, self._quit)

        # Прописываем себя в автозапуск Windows (один раз)
        self._register_autostart()

        if not self.config.get("setup_done"):
            self.root.after(400, self._setup)
        elif self._autostart:
            # Автозапуск: прячемся в трей, ждём пока система загрузится
            self.root.after(100, self._boot_silent)
        else:
            self.root.after(600, self._greet)

        self.root.after(300, self._start_mic)
        self._tick()
        self._animate()

    # ──────────────────────────────────────────────────────
    # UI
    # ──────────────────────────────────────────────────────
    # ══════════════════════════════════════════════════════
    # ПОСТРОЕНИЕ ОКНА
    # ══════════════════════════════════════════════════════
    # ═══════════════════════════════════════════════════
    # UI — SCARLETT DARK GLASS DESIGN
    # ═══════════════════════════════════════════════════
    def _build_ui(self):
        self.root = tk.Tk()
        self.root.title("Scarlett")
        self.root.configure(bg=C["bg"])
        self.root.geometry("440x740")
        self.root.minsize(380, 540)
        self.root.attributes("-alpha", 0.97)
        self.root.attributes("-topmost", True)
        # Убираем системный titlebar Windows (перо питона + Win-кнопки)
        self.root.overrideredirect(True)
        # Иконка в таскбаре и заголовке
        if _ICON_PATH:
            try: self.root.iconbitmap(_ICON_PATH)
            except: pass
        # Регистрируем как отдельное приложение (иконка в taskbar)
        try:
            ctypes.windll.shell32.SetCurrentProcessExplicitAppUserModelID(
                u"Onemore.Scarlett.AI.2")
        except: pass
        # Показываем кнопку в taskbar несмотря на overrideredirect
        try:
            self.root.after(100, lambda: self._fix_taskbar())
        except: pass
        sw = self.root.winfo_screenwidth()
        sh = self.root.winfo_screenheight()
        # Сначала рисуем без позиции, потом после отрисовки ставим
        def _fix_pos():
            W2 = self.root.winfo_width()
            H2 = self.root.winfo_height()
            x  = sw - W2 - 20
            y  = sh - H2 - 48   # 48 = высота таскбара
            self.root.geometry(f"+{x}+{y}")
        self.root.after(50, _fix_pos)
        self.root.grid_rowconfigure(1, weight=1)
        self.root.grid_columnconfigure(0, weight=1)
        self._build_titlebar()
        self._build_header()
        self._build_chat()
        self._build_input()
        self._build_vis()
        self.root.protocol("WM_DELETE_WINDOW", self._go_sleep)

    # ── КАСТОМНЫЙ ТАЙТЛ-БАР ───────────────────────────────
    def _build_titlebar(self):
        """Тонкая полоска-titlebar с нeon линией"""
        tb = tk.Frame(self.root, bg=C["bg2"], height=28)
        tb.grid(row=0, column=0, sticky="ew")
        tb.grid_propagate(False)
        # Нижняя граница titlebar = neon line
        self._neon_cv = tk.Canvas(tb, height=2, bg=C["bg2"],
                                   highlightthickness=0)
        self._neon_cv.place(x=0, rely=1.0, anchor="sw", relwidth=1)

        tk.Label(tb, text="◆  SCARLETT  AI",
                 font=("Consolas", 8), bg=C["bg2"],
                 fg=C["fg3"]).place(x=10, y=7)

        bf = tk.Frame(tb, bg=C["bg2"])
        bf.place(relx=1.0, x=-6, y=4, anchor="ne")
        self._tbtn(bf, "⚙", self._open_settings, C["fg2"]).pack(side="left", padx=2)
        self._tbtn(bf, "–", self._go_sleep,       C["fg2"]).pack(side="left", padx=2)
        self._tbtn(bf, "✕", self._quit,           C["accent3"]).pack(side="left", padx=2)

        tb.bind("<ButtonPress-1>", self._drag_start)
        tb.bind("<B1-Motion>",     self._drag_move)

    def _fix_taskbar(self):
        """После overrideredirect возвращаем кнопку приложения в taskbar"""
        try:
            import ctypes as _ct
            GWL_EXSTYLE  = -20
            WS_EX_APPWINDOW  = 0x00040000
            WS_EX_TOOLWINDOW = 0x00000080
            hwnd = self.root.winfo_id()
            # Получаем родительский HWND
            hwnd_parent = _ct.windll.user32.GetParent(hwnd)
            style = _ct.windll.user32.GetWindowLongW(hwnd, GWL_EXSTYLE)
            style = (style & ~WS_EX_TOOLWINDOW) | WS_EX_APPWINDOW
            _ct.windll.user32.SetWindowLongW(hwnd, GWL_EXSTYLE, style)
            # Скрываем и показываем — применяет новый стиль
            self.root.withdraw()
            self.root.after(10, self.root.deiconify)
        except: pass

    def _tbtn(self, p, txt, cmd, col):
        c = tk.Canvas(p, width=20, height=20, bg=C["bg2"], highlightthickness=0)
        c.create_text(10, 10, text=txt, font=("Consolas", 9, "bold"),
                       fill=col, tags="t")
        c.bind("<Button-1>", lambda e: cmd())
        c.bind("<Enter>",  lambda e: c.itemconfig("t", fill="white"))
        c.bind("<Leave>",  lambda e: c.itemconfig("t", fill=col))
        return c

    # ── ХЕДЕР ─────────────────────────────────────────────
    def _build_header(self):
        hf = tk.Frame(self.root, bg=C["card"], height=86)
        hf.grid(row=1, column=0, sticky="ew")
        hf.grid_propagate(False)
        self.header_frame = hf

        # Орб
        self.orb_canvas = tk.Canvas(hf, width=62, height=62,
                                     bg=C["card"], highlightthickness=0)
        self.orb_canvas.place(x=16, y=12)

        # Имя + подпись
        tk.Label(hf, text="SCARLETT",
                 font=("Consolas", 17, "bold"),
                 bg=C["card"], fg=C["accent"]).place(x=90, y=10)
        tk.Label(hf, text="Neural Voice Assistant",
                 font=("Segoe UI", 9),
                 bg=C["card"], fg=C["fg2"]).place(x=90, y=40)

        # Статус
        self._sdot = tk.Canvas(hf, width=9, height=9,
                                bg=C["card"], highlightthickness=0)
        self._sdot.place(x=90, y=65)
        self._sdot.create_oval(0,0,8,8, fill=C["ok"], outline="", tags="dot")
        self.status_lbl = tk.Label(hf, text="Активна",
                                    font=("Consolas", 8),
                                    bg=C["card"], fg=C["ok"])
        self.status_lbl.place(x=103, y=63)

        # Правый блок — медиа-кнопки
        rb = tk.Frame(hf, bg=C["card"])
        rb.place(relx=1.0, x=-12, y=20, anchor="ne")
        for ic, fn in [("⏮", lambda: self.brain._media_key(0xB1)),
                        ("⏸", lambda: self.brain._media_key(0xB3)),
                        ("⏭", lambda: self.brain._media_key(0xB0))]:
            self._mbtn(rb, ic, fn).pack(side="left", padx=2)

        hf.bind("<ButtonPress-1>", self._drag_start)
        hf.bind("<B1-Motion>",     self._drag_move)

    def _mbtn(self, parent, icon, cmd):
        c = tk.Canvas(parent, width=28, height=28,
                       bg=C["card"], highlightthickness=0)
        c.create_rectangle(1,1,27,27, fill=C["surface"],
                            outline=C["border"], tags="bg")
        c.create_text(14, 14, text=icon,
                       font=("Segoe UI Emoji", 10), tags="ic")
        c.bind("<Button-1>", lambda e: cmd())
        c.bind("<Enter>", lambda e: c.itemconfig("bg", fill=C["surface2"]))
        c.bind("<Leave>", lambda e: c.itemconfig("bg", fill=C["surface"]))
        return c

    # ── ЧАТ ───────────────────────────────────────────────
    def _build_chat(self):
        outer = tk.Frame(self.root, bg=C["bg"])
        outer.grid(row=2, column=0, sticky="nsew")
        outer.grid_rowconfigure(0, weight=1)
        outer.grid_columnconfigure(0, weight=1)
        self.root.grid_rowconfigure(2, weight=1)

        self.chat_canvas = tk.Canvas(outer, bg=C["bg"],
                                      highlightthickness=0, bd=0)
        sb = tk.Scrollbar(outer, orient="vertical",
                           command=self.chat_canvas.yview,
                           bg=C["bg"], troughcolor=C["bg"],
                           activebackground=C["border"], width=4)
        self.chat_canvas.configure(yscrollcommand=sb.set)
        self.chat_canvas.grid(row=0, column=0, sticky="nsew")
        sb.grid(row=0, column=1, sticky="ns")

        self.chat_frame = tk.Frame(self.chat_canvas, bg=C["bg"])
        self._cwin = self.chat_canvas.create_window(
            (0,0), window=self.chat_frame, anchor="nw")
        self.chat_frame.bind("<Configure>", lambda e:
            self.chat_canvas.configure(
                scrollregion=self.chat_canvas.bbox("all")))
        self.chat_canvas.bind("<Configure>", lambda e:
            self.chat_canvas.itemconfig(self._cwin, width=e.width))
        def _on_mousewheel(e):
            self.chat_canvas.yview_scroll(int(-1*(e.delta/120)), "units")
        self.chat_canvas.bind("<MouseWheel>", _on_mousewheel)
        self.chat_frame.bind("<MouseWheel>",  _on_mousewheel)
        self.root.bind_all("<MouseWheel>",    _on_mousewheel)
        self._wheel_cb = _on_mousewheel

        # Передаём скролл от всех виджетов внутри чата
        def _bind_mousewheel_recursive(widget):
            widget.bind("<MouseWheel>", _on_mousewheel, add=True)
            for child in widget.winfo_children():
                _bind_mousewheel_recursive(child)
        self.chat_frame.bind("<Configure>", lambda e: (
            self.chat_canvas.configure(
                scrollregion=self.chat_canvas.bbox("all")),
            _bind_mousewheel_recursive(self.chat_frame)
        ))

    # ── ВВОД ──────────────────────────────────────────────
    def _build_input(self):
        inf = tk.Frame(self.root, bg=C["card"], height=62)
        inf.grid(row=3, column=0, sticky="ew")
        inf.grid_propagate(False)
        inf.grid_columnconfigure(1, weight=1)

        tk.Frame(inf, bg=C["border"], height=1).grid(
            row=0, column=0, columnspan=3, sticky="ew")

        # Иконка mic — пульсирует когда слушает
        self._mic_cv = tk.Canvas(inf, width=40, height=40,
                                  bg=C["card"], highlightthickness=0)
        self._mic_cv.grid(row=1, column=0, padx=(12,6), pady=11)
        self._mic_cv.create_oval(2,2,38,38, fill=C["surface"],
                                  outline=C["border"], tags="mb")
        self._mic_cv.create_text(20,20, text="🎙",
                                  font=("Segoe UI Emoji",13), tags="mi")

        self.input_var = tk.StringVar()
        self.entry = tk.Entry(
            inf, textvariable=self.input_var,
            font=("Segoe UI", 12),
            bg=C["surface"], fg=C["fg"],
            insertbackground=C["accent"],
            relief="flat", bd=0,
            highlightthickness=1,
            highlightcolor=C["accent"],
            highlightbackground=C["border"],
        )
        self.entry.grid(row=1, column=1, sticky="ew", pady=11, ipady=7)

        self._ph = "Команда или голос..."
        self.entry.insert(0, self._ph)
        self.entry.configure(fg=C["fg3"])
        self.entry.bind("<FocusIn>",  self._entry_focus_in)
        self.entry.bind("<FocusOut>", self._entry_focus_out)
        self.entry.bind("<Return>",   self._submit)
        self.entry.bind("<KP_Enter>", self._submit)

        send = tk.Canvas(inf, width=40, height=40,
                          bg=C["card"], highlightthickness=0)
        send.grid(row=1, column=2, padx=(6,12), pady=11)
        send.create_oval(1,1,39,39, fill=C["accent"], outline="", tags="sb")
        send.create_text(20,20, text="↑", fill="white",
                          font=("Consolas",16,"bold"))
        send.bind("<Button-1>", self._submit)
        send.bind("<Enter>", lambda e: send.itemconfig("sb", fill=C["accent2"]))
        send.bind("<Leave>", lambda e: send.itemconfig("sb", fill=C["accent"]))

    # ── ВИЗУАЛИЗАТОР ──────────────────────────────────────
    def _build_vis(self):
        vf = tk.Frame(self.root, bg=C["card"], height=36)
        vf.grid(row=4, column=0, sticky="ew")
        vf.grid_propagate(False)
        self.vis_canvas = tk.Canvas(vf, bg=C["card"],
                                     height=36, highlightthickness=0)
        self.vis_canvas.pack(fill="x", expand=True)

    # ── ТЕКСТОВЫЙ ВВОД ────────────────────────────────────
    def _entry_focus_in(self, e):
        if self.input_var.get() == self._ph:
            self.entry.delete(0, "end")
            self.entry.configure(fg=C["fg"])

    def _entry_focus_out(self, e):
        if not self.input_var.get().strip():
            self.entry.insert(0, self._ph)
            self.entry.configure(fg=C["fg3"])

    def _submit(self, event=None):
        text = self.input_var.get().strip()
        if not text or text == self._ph:
            return "break"
        self.entry.delete(0, "end")
        self._handle(text)
        return "break"

