    def _normalize(self, text):
        import re as _re
        t = text.lower().strip()

        # 1. Фонетические исправления — многословные фразы первыми (длинные раньше)
        for phrase in sorted(self._PHONETIC_MAP, key=len, reverse=True):
            if phrase in t:
                t = t.replace(phrase, self._PHONETIC_MAP[phrase])

        # 2. Числа словами → цифры (целые слова)
        words_to_nums = [
            ("ноль","0"),("один","1"),("два","2"),("три","3"),
            ("четыре","4"),("пять","5"),("шесть","6"),
            ("семь","7"),("восемь","8"),("девять","9"),
            ("десять","10"),("двадцать","20"),("тридцать","30"),
            ("сорок","40"),("пятьдесят","50"),("шестьдесят","60"),
            ("семьдесят","70"),("восемьдесят","80"),
            ("девяносто","90"),("сто","100"),
        ]
        for word, num in words_to_nums:
            t = _re.sub(r"(?<![a-zа-яё])" + word + r"(?![a-zа-яё])", num, t)

        # 3. Отдельные слова (целые, regex)
        fixes = [
            (r"\b(stop|стом|стон)\b",   "стоп"),
            (r"\bplay\b",               "играй"),
            (r"\bтг\b",                 "телеграм"),
            (r"\bгс\b",                 "genshin"),
            (r"\bкс\s*2\b",             "кс2"),
            (r"\bcs\s*2\b",             "кс2"),
            (r"\bгта\s*5\b",            "гта"),
            (r"\bгта\s*v\b",            "гта"),
        ]
        for pat, repl in fixes:
            t = _re.sub(pat, repl, t)

        return t

    def _handle(self, text):
        if not text.strip(): return
        text = self._normalize(text)
        if self.sleeping:
            if any(w in text.lower() for w in self.WAKE_WORDS):
                self._wake_up()
            return
        self._add_msg(text, user=True)
        self._set_status("Думаю...", C["warn"])
        self._processing = True
        def _bg():
            resp, action = self.brain.process(text)
            self.q.put(("resp", resp, action))
        threading.Thread(target=_bg, daemon=True).start()

    def _tick(self):
        try:
            while True:
                item = self.q.get_nowait()
                if item[0] == "resp":
                    _, resp, action = item
                    self._processing = False
                    self._add_msg(resp, user=False)
                    if action == "sleep":
                        self.tts.speak(resp, done_cb=self._go_sleep)
                    else:
                        self.tts.speak(resp)
                        self._set_status("Активна", C["ok"])
                elif item[0] == "voice":
                    self._handle(item[1])
                elif item[0] == "status":
                    self._set_status(item[1], item[2])
        except queue.Empty:
            pass
        self.root.after(80, self._tick)

    def _start_mic(self):
        if not self.mic.has_audio:
            self.q.put(("status","Только текст",C["warn"]))
            self._add_msg("PyAudio не установлен. Запусти install.bat!", user=False)
            return
        ok = self.mic.start(lambda t: self.q.put(("voice", t)))
        self.q.put(("status",
                    "Слушаю..." if ok else "Микрофон недоступен",
                    C["ok"] if ok else C["warn"]))

    def _go_sleep(self):
        self.sleeping = True
        self._set_status("В трее...", C["fg3"])
        self.root.withdraw()
        self.tray.show()

    def _wake_up(self):
        self.sleeping = False
        self.tray.hide()
        self.root.deiconify()
        self.root.lift()
        self.root.focus_force()
        self._set_status("Активна", C["ok"])
        name = self.config.get("user_name","друг")
        resp = f"Привет, {name}! Я снова здесь!"
        self._add_msg(resp, user=False)
        self.tts.speak(resp)

    # ── СООБЩЕНИЯ ─────────────────────────────────────────
    def _add_msg(self, text: str, user: bool):
        ts = datetime.datetime.now().strftime("%H:%M")
        outer = tk.Frame(self.chat_frame, bg=C["bg"])
        outer.pack(fill="x", padx=12, pady=4)

        # Прокидываем MouseWheel на все дочерние виджеты
        def _bind_wheel(widget):
            if hasattr(self, "_wheel_cb"):
                widget.bind("<MouseWheel>", self._wheel_cb)
            for child in widget.winfo_children():
                _bind_wheel(child)
        self.root.after(90, lambda: _bind_wheel(outer))

        if user:
            # ── Пользователь — справа ─────────────────────
            wrap = tk.Frame(outer, bg=C["bg"])
            wrap.pack(side="right")
            # Маленькая плашка с временем
            tk.Label(wrap, text=ts, font=("Consolas", 7),
                     bg=C["bg"], fg=C["fg3"]).pack(anchor="e", pady=(0,1))
            # Пузырь
            bub = tk.Frame(wrap, bg=C["ubub"], padx=14, pady=9)
            bub.pack(anchor="e")
            # Правая акцентная полоска
            stripe = tk.Frame(bub, bg=C["accent"], width=3)
            stripe.pack(side="right", fill="y", padx=(8,0))
            tk.Label(bub, text=text,
                     font=("Segoe UI", 11),
                     bg=C["ubub"], fg=C["fg"],
                     wraplength=285, justify="right").pack(side="right")

        else:
            # ── Scarlett — слева ──────────────────────────
            row = tk.Frame(outer, bg=C["bg"])
            row.pack(side="left", fill="x", expand=True)

            # Аватар-орб (маленький)
            av = tk.Canvas(row, width=36, height=36,
                            bg=C["bg"], highlightthickness=0)
            av.pack(side="left", anchor="n", padx=(0,10), pady=2)
            for i in range(16,0,-3):
                col = self._lerp(C["accent"],C["accent2"],1-i/16)
                av.create_oval(18-i,18-i,18+i,18+i,fill=col,outline="")
            av.create_text(18,18,text="S",
                            font=("Consolas",11,"bold"),fill="white")

            right = tk.Frame(row, bg=C["bg"])
            right.pack(side="left", fill="x", expand=True)

            # Имя + время
            nrow = tk.Frame(right, bg=C["bg"])
            nrow.pack(anchor="w")
            tk.Label(nrow, text="Scarlett",
                     font=("Consolas", 9, "bold"),
                     bg=C["bg"], fg=C["accent"]).pack(side="left")
            tk.Label(nrow, text=f"  {ts}",
                     font=("Consolas", 7),
                     bg=C["bg"], fg=C["fg3"]).pack(side="left", pady=(1,0))

            # Пузырь с левой голубой чертой
            bub = tk.Frame(right, bg=C["bbub"])
            bub.pack(anchor="w", fill="x", pady=(2,0))
            tk.Frame(bub, bg=C["accent2"], width=3).pack(
                side="left", fill="y")
            tk.Label(bub, text=text,
                     font=("Segoe UI", 11),
                     bg=C["bbub"], fg=C["fg"],
                     wraplength=305, justify="left",
                     padx=12, pady=9).pack(side="left", anchor="w")

        # Надёжный скролл через winfo_reqheight
        def _scroll_to_bottom():
            self.chat_frame.update_idletasks()
            h = self.chat_frame.winfo_reqheight()
            self.chat_canvas.configure(scrollregion=(0, 0, 0, h))
            self.chat_canvas.yview_moveto(1.0)
        self.root.after(20,  _scroll_to_bottom)
        self.root.after(150, _scroll_to_bottom)
        self.root.after(500, _scroll_to_bottom)
        # Биндим колёсико на новые виджеты сообщения
        try:
            self._bind_all_scroll(outer)
        except:
            pass

    def _bind_all_scroll(self, widget):
        """Рекурсивно вешает mousewheel скролл чата на виджет и всех потомков"""
        try:
            widget.bind("<MouseWheel>", self._wheel_cb, add=True)
            for child in widget.winfo_children():
                self._bind_all_scroll(child)
        except:
            pass

    # ── АНИМАЦИЯ ──────────────────────────────────────────
    def _animate(self):
        self.frame += 1
        f = self.frame

        # ── Орб ───────────────────────────────────────────
        c = self.orb_canvas
        c.delete("all")
        cx = cy = 31; r = 26

        if self.sleeping:
            p = 0.5 + 0.35*math.sin(f*0.032)
            c.create_oval(cx-r-5,cy-r-5,cx+r+5,cy+r+5, fill="",
                           outline=self._lerp(C["bg2"],C["accent2"],p*0.25),width=1)
            c.create_oval(cx-r,cy-r,cx+r,cy+r,
                           fill=self._lerp(C["surface"],"#06070F",p),outline="")
            c.create_text(cx,cy,text="💤",font=("Segoe UI Emoji",15))

        elif self._processing:
            a0 = f*0.22
            for i in range(12):
                a = a0 + i*(2*math.pi/12)
                fade = (math.sin(a-a0*0.6)+1)/2
                pr = r-2
                x = cx+pr*math.cos(a); y = cy+pr*math.sin(a)
                sz = 1.5+fade*3
                c.create_oval(x-sz,y-sz,x+sz,y+sz,
                               fill=self._lerp(C["accent"],C["accent2"],fade),
                               outline="")
            c.create_oval(cx-9,cy-9,cx+9,cy+9, fill=C["surface2"],outline="")
            rot = "↻" if (f//8)%2==0 else "↺"
            c.create_text(cx,cy,text=rot,
                           font=("Consolas",15,"bold"),fill=C["accent"])

        else:
            pulse = 0.87+0.13*math.sin(f*0.052)
            # Свечение
            for gi in range(6,0,-1):
                gr = r+gi*2.2
                c.create_oval(cx-gr,cy-gr,cx+gr,cy+gr, fill="",
                               outline=self._lerp(C["bg"],C["accent"],gi/40),
                               width=1)
            # Шар
            rr = int(r*pulse)
            for i in range(rr,0,-2):
                col = self._lerp(C["accent2"],C["accent"],i/rr)
                c.create_oval(cx-i,cy-i,cx+i,cy+i,fill=col,outline="")
            # Блик
            sh = 3*math.sin(f*0.02)
            c.create_oval(cx-10+sh,cy-13,cx-5+sh,cy-9,
                           fill="white",outline="",stipple="gray25")
            c.create_text(cx,cy+1,text="S",
                           font=("Consolas",14,"bold"),fill="white")

        # ── Неоновая линия titlebar ────────────────────────
        nl = self._neon_cv
        nl.delete("all")
        w_px = self.root.winfo_width() or 440
        for i in range(80):
            r2 = (math.sin(f*0.042+i*0.14)+1)/2
            col = self._lerp(C["accent"],C["accent2"],r2)
            x0 = i*w_px//80; x1 = (i+1)*w_px//80+1
            nl.create_rectangle(x0,0,x1,2,fill=col,outline="")

        # ── Mic пульс ─────────────────────────────────────
        mc = self._mic_cv
        if not self.sleeping and not self._processing:
            pulse_col = self._lerp(C["surface"],C["accent"],
                                    0.15+0.12*math.sin(f*0.08))
            mc.itemconfig("mb", fill=pulse_col)

        # ── Визуализатор ──────────────────────────────────
        vc = self.vis_canvas
        vc.delete("all")
        vw = max(vc.winfo_width(),440); vh = 36; n = 64

        for i in range(n):
            if self._processing:
                amp = 10+8*math.sin(f*0.26+i*0.51)+\
                      3*math.sin(f*0.53+i*0.88)+random.uniform(-1,1)
            elif not self.sleeping:
                amp = 2.5+2*math.sin(f*0.062+i*0.36)+\
                      1*math.sin(f*0.11+i*0.72)
            else:
                amp = 1+0.5*math.sin(f*0.022+i*0.17)
            x = i*vw/n+vw/n/2
            col = self._lerp(C["accent"],C["accent2"],i/n)
            bw = vw/n*0.54
            vc.create_rectangle(x-bw/2,vh/2-amp,x+bw/2,vh/2+amp,
                                  fill=col,outline="")

        self.root.after(38, self._animate)

    @staticmethod
    def _lerp(c1, c2, t):
        t = max(0.0,min(1.0,t))
        r1,g1,b1=int(c1[1:3],16),int(c1[3:5],16),int(c1[5:7],16)
        r2,g2,b2=int(c2[1:3],16),int(c2[3:5],16),int(c2[5:7],16)
        return "#{:02x}{:02x}{:02x}".format(
            int(r1+(r2-r1)*t),int(g1+(g2-g1)*t),int(b1+(b2-b1)*t))

    def _set_status(self, text, color=None):
        c = color or C["ok"]
        self.status_lbl.configure(text=text, fg=c)
        self._sdot.itemconfig("dot", fill=c)

    # ══════════════════════════════════════════════════════
    # ПРИВЕТСТВИЕ
    # ══════════════════════════════════════════════════════
    def _register_autostart(self):
        """Прописывает Scarlett в реестр HKCU Run — без прав администратора.
        Использует pythonw.exe (нет консоли) + --autostart флаг.
        Если запись уже актуальна — ничего не делает."""
        try:
            import winreg, shutil

            # Находим правильный pythonw.exe — venv приоритет
            here = os.path.dirname(os.path.abspath(
                sys.executable if getattr(sys, "frozen", False) else __file__))

            pythonw = os.path.join(here, "venv", "Scripts", "pythonw.exe")
            if not os.path.exists(pythonw):
                # Пробуем рядом с текущим интерпретатором
                pythonw = os.path.join(os.path.dirname(sys.executable), "pythonw.exe")
            if not os.path.exists(pythonw):
                pythonw = shutil.which("pythonw") or sys.executable

            script = os.path.join(here, "scarlett.py")
            # Команда: pythonw.exe "C:/Scarlett/scarlett.py" --autostart
            cmd = f'"{pythonw}" "{script}" --autostart'

            key_path = r"Software\Microsoft\Windows\CurrentVersion\Run"
            key = winreg.OpenKey(winreg.HKEY_CURRENT_USER,
                                  key_path, 0, winreg.KEY_READ | winreg.KEY_SET_VALUE)

            # Проверяем — может уже записано то же самое
            try:
                existing, _ = winreg.QueryValueEx(key, "Scarlett AI")
                if existing == cmd:
                    winreg.CloseKey(key)
                    print("[Autostart] Already registered, skip")
                    return
            except FileNotFoundError:
                pass  # Записи нет — создадим

            winreg.SetValueEx(key, "Scarlett AI", 0, winreg.REG_SZ, cmd)
            winreg.CloseKey(key)
            print(f"[Autostart] Registered OK: {cmd}")

        except PermissionError:
            print("[Autostart] Permission denied — run as user, not admin")
        except Exception as e:
            print(f"[Autostart] Error: {e}")

    def _unregister_autostart(self):
        """Убирает Scarlett из автозапуска (вызывается из настроек)"""
        try:
            import winreg
            key = winreg.OpenKey(winreg.HKEY_CURRENT_USER,
                                  r"Software\Microsoft\Windows\CurrentVersion\Run",
                                  0, winreg.KEY_SET_VALUE)
            winreg.DeleteValue(key, "Scarlett AI")
            winreg.CloseKey(key)
            print("[Autostart] Removed from registry")
            return True
        except FileNotFoundError:
            return False  # Не было записи
        except Exception as e:
            print(f"[Autostart] Remove error: {e}")
            return False

    def _is_autostart_enabled(self) -> bool:
        """Проверяет — прописана ли Scarlett в автозапуске"""
        try:
            import winreg
            key = winreg.OpenKey(winreg.HKEY_CURRENT_USER,
                                  r"Software\Microsoft\Windows\CurrentVersion\Run",
                                  0, winreg.KEY_READ)
            winreg.QueryValueEx(key, "Scarlett AI")
            winreg.CloseKey(key)
            return True
        except:
            return False

    def _boot_silent(self):
        """Тихий старт при автозагрузке — сразу в трей, без звука"""
        self.sleeping = True
        self.root.withdraw()
        self.tray.show()
        print("[Boot] Silent start — hidden to tray")
        # Через 15 сек (система успела загрузиться) — умное приветствие
        self.root.after(15_000, self._smart_greet)

    def _smart_greet(self):
        """Умное приветствие при автозапуске — по времени суток + погода"""
        name = self.config.get("user_name", "")
        name_str = f", {name}" if name else ""
        h = datetime.datetime.now().hour

        if 5 <= h < 12:
            time_greet = f"Доброе утро{name_str}!"
        elif 12 <= h < 17:
            time_greet = f"Добрый день{name_str}!"
        elif 17 <= h < 23:
            time_greet = f"Добрый вечер{name_str}!"
        else:
            time_greet = f"Не спишь{name_str}?"

        # Статистика — сколько дней Скарлетт уже работает
        install_date = self.config.get("install_date")
        if not install_date:
            install_date = datetime.datetime.now().strftime("%Y-%m-%d")
            self.config["install_date"] = install_date
            save_config(self.config)
        try:
            days = (datetime.datetime.now() -
                    datetime.datetime.strptime(install_date, "%Y-%m-%d")).days
            stat = f" Вместе уже {days} {'день' if days==1 else 'дня' if 2<=days<=4 else 'дней'}." if days > 0 else ""
        except:
            stat = ""

        msg = f"{time_greet} Система готова.{stat}"
        print(f"[Boot] Smart greet: {msg}")

        # Озвучиваем — но не показываем окно
        self.tray.show()  # убедимся что трей есть
        self._add_msg(msg, user=False)
        self.tts.speak(msg)

    def _greet(self):
        name = self.config.get("user_name","")
        g = (f"Привет{', '+name if name else ''}! "
             f"Я Scarlett — твой голосовой ассистент. "
             f"Говори или пиши команду!")
        self._add_msg(g, user=False)
        self.tts.speak(g)
        self._set_status("Активна", C["ok"])

    # ══════════════════════════════════════════════════════
    # ОКНО ПЕРВОНАЧАЛЬНОЙ НАСТРОЙКИ
    # ══════════════════════════════════════════════════════
    def _setup(self):
        """
        Многошаговый wizard первоначальной настройки.
        Шаг 1 — Приветствие + имя
        Шаг 2 — Выбор микрофона + live-калибровка
        Шаг 3 — Готово!
        """
        W, H = 520, 580
        dlg = tk.Toplevel(self.root)
        dlg.title("Настройка Scarlett")
        dlg.configure(bg=C["bg"])
        dlg.geometry(f"{W}x{H}")
        dlg.attributes("-topmost", True)
        dlg.resizable(False, False)
        dlg.overrideredirect(True)
        if _ICON_PATH:
            try: dlg.iconbitmap(_ICON_PATH)
            except: pass
        # Перетаскивание диалога
        def _dlg_drag_start(e, d=dlg): d._dx=e.x; d._dy=e.y
        def _dlg_drag_move(e, d=dlg):
            d.geometry(f"+{d.winfo_x()+e.x-d._dx}+{d.winfo_y()+e.y-d._dy}")
        sw2 = dlg.winfo_screenwidth(); sh2 = dlg.winfo_screenheight()
        dlg.geometry(f"{W}x{H}+{(sw2-W)//2}+{(sh2-H)//2}")
        dlg.grab_set()
        dlg.protocol("WM_DELETE_WINDOW", lambda: None)  # нельзя закрыть крестиком

        # ══════════════════════════════════════════════════
        # Внутреннее состояние wizard
        # ══════════════════════════════════════════════════
        state = {
            "step": 0,          # текущий шаг 0/1/2
            "name": "",
            "city": "Москва",
            "mic_idx": None,
            "mic_level": 0.0,   # текущий уровень громкости
            "calibrating": False,
            "calib_done": False,
            "calib_thread": None,
            "anim_frame": 0,
            "alive": True,
        }

        # ══════════════════════════════════════════════════
        # ОБЩИЙ КАРКАС
        # ══════════════════════════════════════════════════
        # Верхняя неоновая полоска
        top_cv = tk.Canvas(dlg, height=3, bg=C["bg"], highlightthickness=0)
        top_cv.pack(fill="x")
        def _draw_topbar():
            top_cv.delete("all")
            w2 = top_cv.winfo_width() or W
            for i in range(100):
                col = self._lerp(C["accent"], C["accent2"], i/100)
                top_cv.create_rectangle(i*w2//100,0,(i+1)*w2//100+1,3,
                                         fill=col,outline="")
        top_cv.bind("<Configure>", lambda e: _draw_topbar())
        dlg.after(50, _draw_topbar)

        # Индикатор шагов
        steps_cv = tk.Canvas(dlg, height=40, bg=C["bg"], highlightthickness=0)
        steps_cv.pack(fill="x", padx=40, pady=(14,0))

        def _draw_steps():
            steps_cv.delete("all")
            w2 = steps_cv.winfo_width() or (W-80)
            labels = ["Знакомство", "Микрофон", "Готово"]
            n = len(labels)
            step = state["step"]
            cx_list = [int(w2 * (i+0.5) / n) for i in range(n)]

            # Линии между кружками
            for i in range(n-1):
                x1, x2 = cx_list[i]+16, cx_list[i+1]-16
                done = i < step
                col = self._lerp(C["accent"], C["accent2"], i/(n-1)) if done else C["border"]
                steps_cv.create_line(x1,20,x2,20, fill=col, width=2)

            for i, (cx, lbl) in enumerate(zip(cx_list, labels)):
                if i < step:      # пройден
                    fill = C["ok"]; tc = "white"; txt = "✓"
                elif i == step:   # текущий
                    fill = C["accent"]; tc = "white"; txt = str(i+1)
                else:             # будущий
                    fill = C["surface"]; tc = C["fg3"]; txt = str(i+1)
                steps_cv.create_oval(cx-16,4,cx+16,36, fill=fill, outline="")
                steps_cv.create_text(cx,20, text=txt,
                                      font=("Consolas",10,"bold"), fill=tc)
                col_lbl = C["accent"] if i==step else (C["ok"] if i<step else C["fg3"])
                steps_cv.create_text(cx,38, text=lbl,
                                      font=("Segoe UI",8), fill=col_lbl)

        steps_cv.bind("<Configure>", lambda e: _draw_steps())
        dlg.after(60, _draw_steps)

        # Разделитель
        tk.Frame(dlg, bg=C["border"], height=1).pack(fill="x", padx=20, pady=(10,0))

        # Основной контейнер — меняем содержимое при смене шага
        body = tk.Frame(dlg, bg=C["bg"])
        body.pack(fill="both", expand=True, padx=36, pady=0)

        # Нижняя неоновая полоска
        bot_cv = tk.Canvas(dlg, height=3, bg=C["bg"], highlightthickness=0)
        bot_cv.pack(fill="x", side="bottom")
        def _draw_botbar():
            bot_cv.delete("all")
            w2 = bot_cv.winfo_width() or W
            for i in range(100):
                col = self._lerp(C["accent2"], C["accent"], i/100)
                bot_cv.create_rectangle(i*w2//100,0,(i+1)*w2//100+1,3,
                                         fill=col,outline="")
        bot_cv.bind("<Configure>", lambda e: _draw_botbar())
        dlg.after(50, _draw_botbar)

        # ══════════════════════════════════════════════════
        # ВСПОМОГАТЕЛЬНЫЕ ВИДЖЕТЫ
        # ══════════════════════════════════════════════════
        def _clear_body():
            for w in body.winfo_children():
                w.destroy()

        def _grad_btn(parent, text, cmd, h=48):
            cv = tk.Canvas(parent, height=h, bg=C["bg"], highlightthickness=0)
            cv.pack(fill="x", pady=(4,0))
            def _draw(hover=False):
                cv.delete("all")
                bw = cv.winfo_width() or (W-72)
                c1 = C["accent2"] if hover else C["accent"]
                c2 = C["accent"]  if hover else C["accent2"]
                for i in range(bw):
                    cv.create_rectangle(i,0,i+1,h,
                                         fill=self._lerp(c1,c2,i/bw),outline="")
                cv.create_text(bw//2,h//2, text=text,
                                font=("Consolas",12,"bold"), fill="white")
            cv.bind("<Configure>", lambda e: _draw())
            cv.bind("<Enter>",     lambda e: _draw(True))
            cv.bind("<Leave>",     lambda e: _draw(False))
            cv.bind("<Button-1>",  lambda e: cmd())
            return cv

        def _outline_entry(parent, var, placeholder=""):
            wrap = tk.Frame(parent, bg=C["surface"],
                             highlightthickness=1,
                             highlightbackground=C["border"])
            wrap.pack(fill="x", pady=(4,0))
            ent = tk.Entry(wrap, textvariable=var,
                            font=("Segoe UI",13),
                            bg=C["surface"], fg=C["fg"],
                            insertbackground=C["accent"],
                            relief="flat", bd=10)
            ent.pack(fill="x")
            if placeholder:
                ent.insert(0, placeholder)
                ent.configure(fg=C["fg3"])
                def fi(e):
                    if ent.get()==placeholder:
                        ent.delete(0,"end"); ent.configure(fg=C["fg"])
                    wrap.configure(highlightbackground=C["accent"])
                def fo(e):
                    if not ent.get().strip():
                        ent.insert(0,placeholder); ent.configure(fg=C["fg3"])
                    wrap.configure(highlightbackground=C["border"])
                ent.bind("<FocusIn>",fi); ent.bind("<FocusOut>",fo)
            else:
                ent.bind("<FocusIn>",  lambda e: wrap.configure(
                    highlightbackground=C["accent"]))
                ent.bind("<FocusOut>", lambda e: wrap.configure(
                    highlightbackground=C["border"]))
            return ent, wrap

        # ══════════════════════════════════════════════════
        # ШАГ 0 — ПРИВЕТСТВИЕ + ИМЯ
        # ══════════════════════════════════════════════════
        def show_step0():
            _clear_body()
            state["step"] = 0
            dlg.after(10, _draw_steps)

            # Орб с анимацией
            orb_f = tk.Frame(body, bg=C["bg"])
            orb_f.pack(pady=(18,0))
            orb_c = tk.Canvas(orb_f, width=96, height=96,
                               bg=C["bg"], highlightthickness=0)
            orb_c.pack()

            _of = [0]
            def _orb_anim():
                if not state["alive"] or not dlg.winfo_exists(): return
                try:
                    if not orb_c.winfo_exists(): return
                    _of[0]+=1
                    orb_c.delete("all")
                    p = 0.86+0.14*math.sin(_of[0]*0.065)
                    for i in range(int(42*p),0,-4):
                        col = self._lerp(C["accent2"],C["accent"],1-i/(42*p))
                        orb_c.create_oval(48-i,48-i,48+i,48+i,fill=col,outline="")
                    orb_c.create_oval(28,18,40,27,fill="white",outline="",stipple="gray25")
                    orb_c.create_text(48,49,text="S",
                                       font=("Consolas",24,"bold"),fill="white")
                    dlg.after(40, _orb_anim)
                except Exception: return
            dlg.after(40, _orb_anim)

            tk.Label(body, text="Привет! Я Scarlett",
                     font=("Consolas",17,"bold"),
                     bg=C["bg"], fg=C["accent"]).pack(pady=(10,2))
            tk.Label(body,
                     text="Твой персональный голосовой ассистент.\nКак мне тебя называть?",
                     font=("Segoe UI",10),
                     bg=C["bg"], fg=C["fg2"],
                     justify="center").pack()

            tk.Frame(body, bg=C["border"], height=1).pack(
                fill="x", pady=16)

            # Поле имени
            tk.Label(body, text="Твоё имя:",
                     font=("Consolas",10,"bold"),
                     bg=C["bg"], fg=C["fg"]).pack(anchor="w")
            name_var = tk.StringVar()
            name_ent, _ = _outline_entry(body, name_var)
            name_ent.focus_set()

            # Поле города
            tk.Label(body, text="Город (для погоды):",
                     font=("Consolas",10,"bold"),
                     bg=C["bg"], fg=C["fg"]).pack(anchor="w", pady=(12,0))
            city_var = tk.StringVar(value="Москва")
            _outline_entry(body, city_var)

            # Превью как будет звучать
            preview_lbl = tk.Label(body, text="",
                                    font=("Segoe UI",9,"italic"),
                                    bg=C["bg"], fg=C["accent2"])
            preview_lbl.pack(pady=(10,0))

            def _update_preview(*args):
                n = name_var.get().strip()
                if n:
                    preview_lbl.configure(
                        text=f'Скарлетт будет говорить: "Привет, {n}!"')
                else:
                    preview_lbl.configure(text="")
            name_var.trace_add("write", _update_preview)

            def next_step():
                nm = name_var.get().strip()
                ct = city_var.get().strip()
                # Если ввели placeholder — очищаем
                state["name"] = nm if nm else "Пользователь"
                state["city"] = ct if ct else "Москва"
                show_step1()

            _grad_btn(body, "Далее  →", next_step)
            name_ent.bind("<Return>", lambda e: next_step())

        # ══════════════════════════════════════════════════
        # ШАГ 1 — МИКРОФОН + LIVE КАЛИБРОВКА
        # ══════════════════════════════════════════════════
        def show_step1():
            _clear_body()
            state["step"] = 1
            state["calibrating"] = False
            state["calib_done"]  = False
            state["mic_level"]   = 0.0
            dlg.after(10, _draw_steps)

            tk.Label(body, text="Настройка микрофона",
                     font=("Consolas",15,"bold"),
                     bg=C["bg"], fg=C["accent"]).pack(pady=(18,2))
            tk.Label(body,
                     text="Выбери микрофон и откалибруй его — говори\nлюбую фразу во время теста",
                     font=("Segoe UI",9), bg=C["bg"], fg=C["fg2"],
                     justify="center").pack()

            tk.Frame(body, bg=C["border"], height=1).pack(fill="x", pady=12)

            # Список микрофонов
            tk.Label(body, text="Микрофон:",
                     font=("Consolas",10,"bold"),
                     bg=C["bg"], fg=C["fg"]).pack(anchor="w")

            mic_names = ["🎙  Системный по умолчанию"]
            mic_idxs  = [None]
            try:
                import pyaudio as _pa
                p = _pa.PyAudio()
                skip = ["output","вывод","speaker","spdif","stereo mix",
                        "virtual","nvidia","zowie","t238y","lcd",
                        "mapper - output","realtek digital",
                        "лин. вых","линейный выход"]
                for i in range(p.get_device_count()):
                    try:
                        info = p.get_device_info_by_index(i)
                        if info["maxInputChannels"] <= 0: continue
                        if any(k in info["name"].lower() for k in skip): continue
                        mic_names.append(f"[{i}]  {info['name'][:36]}")
                        mic_idxs.append(i)
                    except: continue
                p.terminate()
            except: pass

            def_sel = 0
            try:
                import pyaudio as _pa2
                p2 = _pa2.PyAudio()
                di = p2.get_default_input_device_info()["index"]
                p2.terminate()
                for mi,idx in enumerate(mic_idxs):
                    if idx==di: def_sel=mi; break
            except: pass

            mic_var = tk.StringVar(value=mic_names[def_sel])
            mic_wrap = tk.Frame(body, bg=C["surface"],
                                 highlightthickness=1,
                                 highlightbackground=C["border"])
            mic_wrap.pack(fill="x", pady=(4,0))
            import tkinter.ttk as ttk
            st2 = ttk.Style()
            st2.theme_use("clam")
            st2.configure("S.TCombobox",
                           fieldbackground=C["surface"],
                           background=C["surface2"],
                           foreground=C["fg"],
                           selectbackground=C["accent"],
                           selectforeground="white",
                           arrowcolor=C["accent"],
                           borderwidth=0, relief="flat")
            st2.map("S.TCombobox",
                    fieldbackground=[("readonly",C["surface"])],
                    foreground=[("readonly",C["fg"])])
            mic_cb = ttk.Combobox(mic_wrap, textvariable=mic_var,
                                   values=mic_names,
                                   style="S.TCombobox",
                                   state="readonly",
                                   font=("Segoe UI",10))
            mic_cb.current(def_sel)
            mic_cb.pack(fill="x", ipady=7, padx=2, pady=2)

            # ── Live-калибровка ────────────────────────────
            calib_frame = tk.Frame(body, bg=C["bg"])
            calib_frame.pack(fill="x", pady=(14,0))

            # Визуализатор уровня (горизонтальный)
            viz_label = tk.Label(calib_frame, text="Уровень сигнала:",
                                  font=("Consolas",9,"bold"),
                                  bg=C["bg"], fg=C["fg"])
            viz_label.pack(anchor="w")

            viz_outer = tk.Frame(calib_frame, bg=C["surface"],
                                  highlightthickness=1,
                                  highlightbackground=C["border"],
                                  height=36)
            viz_outer.pack(fill="x", pady=(4,0))
            viz_outer.pack_propagate(False)
            viz_cv = tk.Canvas(viz_outer, bg=C["surface"],
                                highlightthickness=0, height=36)
            viz_cv.pack(fill="both", expand=True)

            # Гистограмма мини (waveform)
            wave_label = tk.Label(calib_frame, text="Waveform:",
                                   font=("Consolas",9,"bold"),
                                   bg=C["bg"], fg=C["fg"])
            wave_label.pack(anchor="w", pady=(10,0))
            wave_outer = tk.Frame(calib_frame, bg=C["surface"],
                                   highlightthickness=1,
                                   highlightbackground=C["border"],
                                   height=52)
            wave_outer.pack(fill="x", pady=(4,0))
            wave_outer.pack_propagate(False)
            wave_cv = tk.Canvas(wave_outer, bg=C["surface"],
                                 highlightthickness=0, height=52)
            wave_cv.pack(fill="both", expand=True)

            # Буфер семплов для waveform
            wave_buf = [0.0]*60

            # Статус калибровки
            status_var = tk.StringVar(value="Нажми «Тест микрофона» чтобы начать")
            status_lbl2 = tk.Label(calib_frame,
                                    textvariable=status_var,
                                    font=("Segoe UI",9,"italic"),
                                    bg=C["bg"], fg=C["fg2"],
                                    wraplength=420)
            status_lbl2.pack(pady=(8,0))

            # Анимация визуализатора
            def _draw_viz():
                if not state["alive"] or not dlg.winfo_exists():
                    return
                try:
                    if not viz_cv.winfo_exists() or not wave_cv.winfo_exists():
                        return
                    state["anim_frame"] += 1
                    f  = state["anim_frame"]
                    lvl = state["mic_level"]

                    # ── Level bar ──────────────────────────────
                    viz_cv.delete("all")
                    vw = max(viz_cv.winfo_width(), W-100)
                    vh = 36

                    if state["calibrating"]:
                        if lvl < 0.15:
                            status_var.set("🔇 Тихо — говори громче или поднеси микрофон")
                            status_lbl2.configure(fg=C["warn"])
                        elif lvl < 0.5:
                            status_var.set("✓ Хороший уровень — продолжай говорить")
                            status_lbl2.configure(fg=C["ok"])
                        else:
                            status_var.set("⚡ Слишком громко — отодвинь микрофон")
                            status_lbl2.configure(fg=C["accent3"])
                        fill_w = int(vw * min(lvl, 1.0))
                        viz_cv.create_rectangle(0,4,vw,vh-4,
                            fill=C["surface2"], outline="")
                        if fill_w > 0:
                            for i in range(fill_w):
                                c2 = self._lerp(C["ok"], C["accent3"], i/vw*1.2)
                                viz_cv.create_rectangle(i,6,i+1,vh-6,
                                    fill=c2, outline="")
                        opt_x1 = int(vw*0.15); opt_x2 = int(vw*0.5)
                        viz_cv.create_rectangle(opt_x1,2,opt_x2,vh-2,
                            fill="", outline=C["ok"], dash=(3,3), width=1)
                        viz_cv.create_text(vw-4, vh//2,
                            text=f"{int(lvl*100)}%", anchor="e",
                            font=("Consolas",9,"bold"), fill=C["fg"])
                    else:
                        for i in range(20):
                            x = (i*vw//20 + f*3) % vw
                            viz_cv.create_rectangle(x,8,x+vw//25,vh-8,
                                fill=C["fg3"], outline="")
                        viz_cv.create_text(vw//2, vh//2,
                            text="нажми Тест микрофона",
                            font=("Segoe UI",8), fill=C["fg3"])

                    # ── Waveform ───────────────────────────────
                    wave_cv.delete("all")
                    ww = max(wave_cv.winfo_width(), W-100)
                    wh = 52

                    if state["calibrating"]:
                        wave_buf.append(lvl)
                        if len(wave_buf) > 60: wave_buf.pop(0)
                        n = len(wave_buf)
                        for i, v in enumerate(wave_buf):
                            x   = i * ww // n
                            amp = v * (wh//2 - 4)
                            col = self._lerp(C["accent2"], C["accent"], v)
                            wave_cv.create_rectangle(
                                x, wh//2-amp, x+ww//n+1, wh//2+amp,
                                fill=col, outline="")
                        wave_cv.create_line(0,wh//2,ww,wh//2,
                            fill=C["border"], width=1)
                    else:
                        for i in range(ww):
                            amp = 4*math.sin(f*0.04 + i*0.18)
                            wave_cv.create_line(i, wh//2+amp, i+1, wh//2+amp,
                                fill=C["fg3"], width=1)

                    dlg.after(50, _draw_viz)
                except Exception as _e:
                    return

            dlg.after(60, _draw_viz)

            # Поток чтения микрофона
            _stop_test = [False]
            _stream = [None]
            _pa_inst = [None]

            def _start_test():
                sel = mic_cb.current()
                midx = mic_idxs[sel] if sel < len(mic_idxs) else None
                state["mic_idx"] = midx
                state["calibrating"] = True
                state["calib_done"]  = False
                _stop_test[0] = False
                test_btn_cv.itemconfig("tbt", fill=C["accent3"])
                # Меняем текст кнопки
                test_btn_cv.itemconfig("tbtxt", text="⏹ Остановить тест")
                wave_buf.clear()

                def _read_mic():
                    try:
                        import pyaudio, struct, math as _math
                        CHUNK = 1024; RATE = 16000
                        pa = pyaudio.PyAudio()
                        _pa_inst[0] = pa
                        kw = {"format": pyaudio.paInt16,
                              "channels": 1,
                              "rate": RATE,
                              "input": True,
                              "frames_per_buffer": CHUNK}
                        if midx is not None:
                            kw["input_device_index"] = midx
                        stream = pa.open(**kw)
                        _stream[0] = stream
                        while not _stop_test[0]:
                            try:
                                data = stream.read(CHUNK, exception_on_overflow=False)
                                # RMS
                                shorts = struct.unpack(f"{CHUNK}h", data)
                                rms = _math.sqrt(sum(s*s for s in shorts)/CHUNK)
                                # Нормализуем к 0..1 (макс RMS ~8000)
                                lvl = min(rms / 4000.0, 1.0)
                                state["mic_level"] = lvl
                            except:
                                break
                        stream.stop_stream()
                        stream.close()
                        pa.terminate()
                    except Exception as e:
                        print(f"[MicTest] {e}")
                    state["mic_level"] = 0.0

                state["calib_thread"] = threading.Thread(
                    target=_read_mic, daemon=True)
                state["calib_thread"].start()

            def _stop_test_fn():
                _stop_test[0] = True
                state["calibrating"] = False
                state["calib_done"]  = True
                test_btn_cv.itemconfig("tbt", fill=C["accent"])
                test_btn_cv.itemconfig("tbtxt", text="▶ Тест микрофона")
                status_var.set("✓ Калибровка завершена! Нажми Далее.")
                status_lbl2.configure(fg=C["ok"])

            def _toggle_test():
                if state["calibrating"]:
                    _stop_test_fn()
                else:
                    _start_test()

            # Кнопка тест
            test_btn_cv = tk.Canvas(body, height=42, bg=C["bg"],
                                     highlightthickness=0)
            test_btn_cv.pack(fill="x", pady=(12,0))

            def _draw_test_btn():
                test_btn_cv.delete("all")
                bw = test_btn_cv.winfo_width() or (W-72)
                fill = C["accent3"] if state["calibrating"] else C["accent"]
                for i in range(bw):
                    test_btn_cv.create_rectangle(
                        i,0,i+1,42,
                        fill=self._lerp(fill, C["accent2"], i/bw),
                        outline="")
                txt = "⏹ Остановить тест" if state["calibrating"] \
                      else "▶ Тест микрофона"
                test_btn_cv.create_text(bw//2,21, text=txt,
                                         font=("Consolas",11,"bold"),
                                         fill="white", tags="tbtxt")
                test_btn_cv.create_rectangle(0,0,bw,42,
                                              fill="", outline="",
                                              tags="tbt")

            test_btn_cv.bind("<Configure>", lambda e: _draw_test_btn())
            test_btn_cv.bind("<Button-1>",  lambda e: _toggle_test())
            dlg.after(80, _draw_test_btn)

            def next_step2():
                _stop_test[0] = True
                state["calibrating"] = False
                sel = mic_cb.current()
                state["mic_idx"] = mic_idxs[sel] if sel < len(mic_idxs) else None
                show_step2()

            _grad_btn(body, "Далее  →", next_step2)

        # ══════════════════════════════════════════════════
        # ШАГ 2 — ГОТОВО
        # ══════════════════════════════════════════════════
        def show_step2():
            _clear_body()
            state["step"] = 2
            dlg.after(10, _draw_steps)

            # Большая анимированная галочка
            check_c = tk.Canvas(body, width=110, height=110,
                                 bg=C["bg"], highlightthickness=0)
            check_c.pack(pady=(22,0))

            _cf = [0]
            def _check_anim():
                if not state["alive"] or not dlg.winfo_exists(): return
                try:
                    if not check_c.winfo_exists(): return
                    _cf[0] += 1
                    check_c.delete("all")
                    f2 = _cf[0]
                    p = 0.85+0.15*math.sin(f2*0.07)
                    r2 = int(48*p)
                    for i in range(r2,0,-4):
                        col = self._lerp(C["ok"],C["accent2"],1-i/r2)
                        check_c.create_oval(55-i,55-i,55+i,55+i,
                                             fill=col,outline="")
                    check_c.create_oval(35,35,75,75, fill="",
                                         outline="white", width=2)
                    check_c.create_text(55,55, text="✓",
                                         font=("Consolas",26,"bold"),
                                         fill="white")
                    dlg.after(40, _check_anim)
                except Exception: return
            dlg.after(40, _check_anim)

            name = state["name"]
            tk.Label(body, text=f"Всё готово, {name}!",
                     font=("Consolas",16,"bold"),
                     bg=C["bg"], fg=C["ok"]).pack(pady=(10,4))
            tk.Label(body,
                     text="Скарлетт настроена и готова к работе.\n"
                          "Скажи «Скарлетт» чтобы активировать.",
                     font=("Segoe UI",10),
                     bg=C["bg"], fg=C["fg2"],
                     justify="center").pack()

            # Итоговые параметры
            params_f = tk.Frame(body, bg=C["surface"],
                                 highlightthickness=1,
                                 highlightbackground=C["border"])
            params_f.pack(fill="x", pady=18)

            for label, val in [
                ("Имя", state["name"]),
                ("Город", state["city"]),
                ("Микрофон",
                 "Системный по умолчанию" if state["mic_idx"] is None
                 else f"Устройство #{state['mic_idx']}"),
            ]:
                row = tk.Frame(params_f, bg=C["surface"])
                row.pack(fill="x", padx=14, pady=5)
                tk.Label(row, text=label+":",
                         font=("Consolas",9,"bold"),
                         bg=C["surface"], fg=C["fg2"],
                         width=14, anchor="w").pack(side="left")
                tk.Label(row, text=val,
                         font=("Segoe UI",10),
                         bg=C["surface"], fg=C["accent"]).pack(side="left")

            def finish():
                state["alive"] = False
                self.config.update({
                    "user_name":  state["name"],
                    "city":       state["city"],
                    "mic_index":  state["mic_idx"],
                    "setup_done": True,
                })
                save_config(self.config)
                self.brain.config = self.config
                self.mic.config   = self.config
                self.mic._pick_best_mic()
                dlg.destroy()
                self.root.after(300, self._greet)

            _grad_btn(body, "Начать работу  ✨", finish, h=52)

        # ── Запускаем первый шаг ──────────────────────────
        show_step0()

    # ══════════════════════════════════════════════════════
    # НАСТРОЙКИ
    # ══════════════════════════════════════════════════════
    def _open_settings(self):
        W, H = 520, 700
        dlg = tk.Toplevel(self.root)
        dlg.title("Настройки")
        dlg.configure(bg=C["bg"])
        dlg.geometry(f"{W}x{H}")
        dlg.attributes("-topmost", True)
        dlg.resizable(False, False)
        dlg.overrideredirect(True)
        if _ICON_PATH:
            try: dlg.iconbitmap(_ICON_PATH)
            except: pass
        # Перетаскивание диалога
        def _dlg_drag_start(e, d=dlg): d._dx=e.x; d._dy=e.y
        def _dlg_drag_move(e, d=dlg):
            d.geometry(f"+{d.winfo_x()+e.x-d._dx}+{d.winfo_y()+e.y-d._dy}")
        sw2 = dlg.winfo_screenwidth(); sh2 = dlg.winfo_screenheight()
        dlg.geometry(f"{W}x{H}+{(sw2-W)//2}+{(sh2-H)//2}")
        # grab_set убрали — он блокировал скролл и вставку

        # Верхняя полоска
        top_cv = tk.Canvas(dlg, height=3, bg=C["bg"], highlightthickness=0)
        top_cv.pack(fill="x")
        def _dtop():
            top_cv.delete("all")
            w2 = top_cv.winfo_width() or W
            for i in range(100):
                top_cv.create_rectangle(
                    i*w2//100,0,(i+1)*w2//100+1,3,
                    fill=self._lerp(C["accent"],C["accent2"],i/100),outline="")
        top_cv.bind("<Configure>", lambda e: _dtop())
        dlg.after(50, _dtop)

        # Заголовок + кнопка закрытия
        hdr = tk.Frame(dlg, bg=C["bg"])
        hdr.pack(fill="x", padx=24, pady=(14,0))
        tk.Label(hdr, text="⚙  НАСТРОЙКИ",
                 font=("Consolas",14,"bold"),
                 bg=C["bg"], fg=C["accent"]).pack(side="left", expand=True)
        close_btn = tk.Button(hdr, text="✕",
                              font=("Consolas",12,"bold"),
                              bg=C["bg"], fg=C["fg2"],
                              activebackground=C["err"],
                              activeforeground="white",
                              relief="flat", bd=0, cursor="hand2",
                              command=dlg.destroy)
        close_btn.pack(side="right")
        close_btn.bind("<Enter>", lambda e: close_btn.config(fg=C["err"]))
        close_btn.bind("<Leave>", lambda e: close_btn.config(fg=C["fg2"]))
        tk.Frame(dlg, bg=C["border"], height=1).pack(fill="x", padx=24, pady=(8,10))

        # ── Прокручиваемое тело ───────────────────────────
        # ── Прокручиваемое тело настроек ──────────────────
        scroll_outer = tk.Frame(dlg, bg=C["bg"])
        scroll_outer.pack(fill="both", expand=True)

        _canvas = tk.Canvas(scroll_outer, bg=C["bg"],
                             highlightthickness=0, bd=0)
        _sb = tk.Scrollbar(scroll_outer, orient="vertical",
                            command=_canvas.yview,
                            bg=C["bg2"], troughcolor=C["bg"],
                            activebackground=C["accent"], width=6)
        _canvas.configure(yscrollcommand=_sb.set)
        _sb.pack(side="right", fill="y")
        _canvas.pack(side="left", fill="both", expand=True)

        body = tk.Frame(_canvas, bg=C["bg"])
        _body_win = _canvas.create_window((0,0), window=body, anchor="nw")

        def _update_scroll(e=None):
            _canvas.configure(scrollregion=_canvas.bbox("all"))
        def _fit_width(e):
            _canvas.itemconfig(_body_win, width=e.width)

        body.bind("<Configure>", _update_scroll)
        _canvas.bind("<Configure>", _fit_width)

        # Скролл колесом — только для этого окна, не трогает чат
        def _on_wheel(e):
            # Проверяем что событие внутри dlg
            w = e.widget
            while w:
                if w == dlg:
                    _canvas.yview_scroll(int(-1*(e.delta/120)), "units")
                    return "break"
                try: w = w.master
                except: break

        def _bind_scroll_recursive(w):
            w.bind("<MouseWheel>", _on_wheel, add="+")
            for child in w.winfo_children():
                _bind_scroll_recursive(child)

        _canvas.bind("<MouseWheel>", _on_wheel)
        body.bind("<MouseWheel>", _on_wheel)
        dlg.bind("<MouseWheel>", _on_wheel)
        body.bind("<Configure>", lambda e: (
            _update_scroll(),
            _bind_scroll_recursive(body)
        ), add=True)

        # При закрытии — снимаем перехват
        def _on_close():
            try: dlg.unbind_all("<MouseWheel>")
            except: pass
            dlg.destroy()
        dlg.protocol("WM_DELETE_WINDOW", _on_close)

        inner = tk.Frame(body, bg=C["bg"])
        inner.pack(fill="both", expand=True, padx=28, pady=4)
        body = inner

        # Финальный bind скролла — после отрисовки всех виджетов
        def _final_bind_scroll():
            def _bind_all(w):
                try: w.bind("<MouseWheel>", _on_wheel, add=True)
                except: pass
                for ch in w.winfo_children():
                    _bind_all(ch)
            _bind_all(dlg)
        dlg.after(300, _final_bind_scroll)
        dlg.after(800, _final_bind_scroll)   # второй раз — после AI секции

        # ── СЕКЦИЯ: Профиль ────────────────────────────────
        self._settings_section(body, "👤  Профиль")

        # Имя
        tk.Label(body, text="Твоё имя:",
                 font=("Consolas",9,"bold"),
                 bg=C["bg"], fg=C["fg"]).pack(anchor="w", pady=(6,2))
        name_var = tk.StringVar(value=self.config.get("user_name",""))
        nw = tk.Frame(body, bg=C["surface"], highlightthickness=1,
                       highlightbackground=C["border"])
        nw.pack(fill="x")
        ne = tk.Entry(nw, textvariable=name_var,
                       font=("Segoe UI",12),
                       bg=C["surface"], fg=C["fg"],
                       insertbackground=C["accent"],
                       relief="flat", bd=8)
        ne.pack(fill="x")
        ne.bind("<FocusIn>",  lambda e: nw.configure(highlightbackground=C["accent"]))
        ne.bind("<FocusOut>", lambda e: nw.configure(highlightbackground=C["border"]))

        # Город
        tk.Label(body, text="Город (погода):",
                 font=("Consolas",9,"bold"),
                 bg=C["bg"], fg=C["fg"]).pack(anchor="w", pady=(10,2))
        city_var = tk.StringVar(value=self.config.get("city","Москва"))
        cw = tk.Frame(body, bg=C["surface"], highlightthickness=1,
                       highlightbackground=C["border"])
        cw.pack(fill="x")
        ce = tk.Entry(cw, textvariable=city_var,
                       font=("Segoe UI",12),
                       bg=C["surface"], fg=C["fg"],
                       insertbackground=C["accent"],
                       relief="flat", bd=8)
        ce.pack(fill="x")
        ce.bind("<FocusIn>",  lambda e: cw.configure(highlightbackground=C["accent"]))
        ce.bind("<FocusOut>", lambda e: cw.configure(highlightbackground=C["border"]))

        # ── СЕКЦИЯ: Тема ───────────────────────────────────
        tk.Frame(body, bg=C["border"], height=1).pack(fill="x", pady=14)
        self._settings_section(body, "🎨  Тема оформления")

        theme_var = tk.StringVar(
            value=self.config.get("theme","Tokyo Night"))

        themes_f = tk.Frame(body, bg=C["bg"])
        themes_f.pack(fill="x", pady=(6,0))

        theme_btns = {}
        cols_per_row = 3
        theme_names = list(THEMES.keys())

        def _draw_theme_btn(name, btn_cv, selected=False):
            btn_cv.delete("all")
            theme = THEMES[name]
            bw = btn_cv.winfo_width() or 130
            bh = btn_cv.winfo_height() or 52
            # Фон
            btn_cv.create_rectangle(0,0,bw,bh,
                fill=theme["surface"] if not selected else theme["accent"],
                outline=theme["accent"] if selected else theme["border"],
                width=2)
            # Превью цветов — 3 полоски
            for ci, ck in enumerate(["accent","accent2","ok"]):
                x = 8 + ci*14
                btn_cv.create_rectangle(x, 8, x+10, 24,
                    fill=theme[ck], outline="")
            # Название
            btn_cv.create_text(bw//2, 37, text=name,
                font=("Segoe UI",8,"bold" if selected else "normal"),
                fill=theme["fg"] if not selected else "white")
            if selected:
                btn_cv.create_text(bw-8, 8, text="✓",
                    font=("Consolas",9,"bold"),
                    fill="white", anchor="ne")

        def _select_theme(name):
            theme_var.set(name)
            for n, cv in theme_btns.items():
                _draw_theme_btn(n, cv, selected=(n==name))
            # Живое превью — применяем тему сразу
            apply_theme(name)
            self._refresh_colors()

        row_f = None
        for idx, name in enumerate(theme_names):
            if idx % cols_per_row == 0:
                row_f = tk.Frame(themes_f, bg=C["bg"])
                row_f.pack(fill="x", pady=2)
            btn_cv = tk.Canvas(row_f, width=130, height=52,
                                bg=C["bg"], highlightthickness=0)
            btn_cv.pack(side="left", padx=3)
            theme_btns[name] = btn_cv
            _n = name  # замыкание
            btn_cv.bind("<Button-1>", lambda e, n=_n: _select_theme(n))
            btn_cv.bind("<Enter>",    lambda e, cv=btn_cv, n=_n:
                cv.configure(cursor="hand2"))
            btn_cv.bind("<Configure>", lambda e, cv=btn_cv, n=_n:
                _draw_theme_btn(n, cv, selected=(n==theme_var.get())))
            dlg.after(80+idx*10, lambda cv=btn_cv, n=_n:
                _draw_theme_btn(n, cv, selected=(n==theme_var.get())))

        # ── СЕКЦИЯ: История ────────────────────────────────
